function ProjectManagementPage({ activeSection = 'Project Overview', onOpenSection, selectedProject, onSelectProject, onNotify }) {
  if (activeSection === 'Project Document Upload') {
    if (selectedProject?.id) {
      return (
        <ProjectSiteSurveyPage
          activeSection="Project Site Survey"
          onOpenSection={onOpenSection}
          project={selectedProject}
          onSelectProject={onSelectProject}
          onNotify={onNotify}
          initialSurveyTab="Documents"
        />
      );
    }
    return (
      <ProjectListPage
        activeSection="Project List"
        onOpenSection={onOpenSection}
        onSelectProject={(project, target = 'Project Site Survey') => onSelectProject?.(project, target)}
        onNotify={onNotify}
      />
    );
  }

  // BUG-007: these action routes used to render ProjectActionPage — a static
  // demo form (hardcoded read-only values, Save just toasted) for ~15 project
  // sub-actions. Redirect to the real list/detail page for that entity instead,
  // same pattern already used for 'Project Document Upload' above: the actual
  // create/edit flows live in tabs/modals on those pages.
  const actionType = projectActionPageTypes[activeSection];
  if (actionType && actionType !== 'document-upload') {
    const projectScopedTarget = {
      activity: 'Project Details',
      note: 'Project Details',
      'progress-update': 'Project Timeline',
    }[actionType];
    if (projectScopedTarget) {
      if (selectedProject?.id) {
        if (projectScopedTarget === 'Project Details') {
          return <ProjectDetailsPage activeSection="Project Details" onOpenSection={onOpenSection} project={selectedProject} onNotify={onNotify} />;
        }
        return <ProjectTimelinePage activeSection="Project Timeline" onOpenSection={onOpenSection} project={selectedProject} onNotify={onNotify} />;
      }
      return <ProjectListPage activeSection="Project List" onOpenSection={onOpenSection} onSelectProject={(project, target = projectScopedTarget) => onSelectProject?.(project, target)} onNotify={onNotify} />;
    }
    const directTarget = {
      create: 'Project List',
      'team-add': 'Project Team Assignment',
      'work-order': 'Project Work Orders',
      'expense-create': 'Project Expenses',
      'expense-detail': 'Project Expenses',
      'document-preview': 'Project Documents',
      'folder-create': 'Project Documents',
      'approval-create': 'Project Approvals',
      'approval-detail': 'Project Approvals',
      'custom-report': 'Project Reports',
      'report-detail': 'Project Reports',
      'report-schedule': 'Project Reports',
    }[actionType] ?? 'Project List';
    return (
      <ProjectManagementPage
        activeSection={directTarget}
        onOpenSection={onOpenSection}
        selectedProject={selectedProject}
        onSelectProject={onSelectProject}
        onNotify={onNotify}
      />
    );
  }

  if (activeSection === 'Project Management' || activeSection === 'Project Overview') {
    return <ProjectListPage activeSection="Project List" onOpenSection={onOpenSection} onSelectProject={onSelectProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Project KPI Analytics') {
    return <ProjectKpiAnalyticsPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project List') {
    return <ProjectListPage activeSection={activeSection} onOpenSection={onOpenSection} onSelectProject={onSelectProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Survey Dashboard') {
    return <SurveyDashboardPage onNotify={onNotify} />;
  }

  if (activeSection === 'Project Details') {
    return <ProjectDetailsPage activeSection={activeSection} onOpenSection={onOpenSection} project={selectedProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Timeline') {
    return <ProjectTimelinePage activeSection={activeSection} onOpenSection={onOpenSection} project={selectedProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Site Survey') {
    return <ProjectSiteSurveyPage activeSection={activeSection} onOpenSection={onOpenSection} project={selectedProject} onSelectProject={onSelectProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Installation') {
    return <ProjectInstallationPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Team Assignment') {
    return <ProjectTeamAssignmentPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Material Planning') {
    return <ProjectMaterialPlanningPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Subsidy') {
    return <ProjectSubsidyPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Work Orders') {
    return <ProjectWorkOrdersPage activeSection={activeSection} onOpenSection={onOpenSection} selectedProject={selectedProject} onSelectProject={onSelectProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Expenses') {
    return <ProjectExpensesPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Documents') {
    return <ProjectDocumentsPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Approvals') {
    return <ProjectApprovalsPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Report View') {
    return <ProjectReportPage activeSection={activeSection} onOpenSection={onOpenSection} project={selectedProject} onSelectProject={onSelectProject} onNotify={onNotify} />;
  }

  if (activeSection === 'Project Reports') {
    if (selectedProject?.id) {
      return (
        <ProjectReportPage
          activeSection="Project Report View"
          onOpenSection={onOpenSection}
          project={selectedProject}
          onNotify={onNotify}
        />
      );
    }
    return (
      <div className="space-y-4">
        <PageHeading
          title="Project Reports"
          crumbs={[
            { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
            { label: 'Project Management', onClick: () => onOpenSection('Project List') },
            { label: 'Project Reports' },
          ]}
        />
        <article className={`${panelClass} p-8 text-center`}>
          <p className="text-[15px] font-extrabold text-[#1e3261]">Select a project to view its report</p>
          <p className="mt-2 text-[13px] font-bold text-[#53647f]">Open a project from Project List, then return here for the live project report.</p>
          <button type="button" onClick={() => onOpenSection('Project List')} className="mt-5 inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#11a650] px-5 text-[13px] font-extrabold text-white transition hover:bg-[#0e9748]">
            Go to Project List
          </button>
        </article>
        <DashboardFooter />
      </div>
    );
  }

  return <ProjectModulePlaceholderPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
}

function ProjectOverviewPage({ activeSection, onOpenSection, onNotify }) {
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const [dateFrom, setDateFrom] = useState('2026-01-01');
  const [dateTo, setDateTo] = useState('2026-12-31');
  const formattedRange = formatProjectDateRange(dateFrom, dateTo);

  const [projects, setProjects] = useState([]);
  const [loadingProjects, setLoadingProjects] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoadingProjects(true);
    projectApi.list({ page_size: 1000 })
      .then((res) => { if (!cancelled) setProjects(Array.isArray(res) ? res : res?.results ?? []); })
      .catch(() => { if (!cancelled) setProjects([]); })
      .finally(() => { if (!cancelled) setLoadingProjects(false); });
    return () => { cancelled = true; };
  }, []);

  const total = projects.length;
  const pct = (n) => (total > 0 ? `${((n / total) * 100).toFixed(1)}%` : '0%');
  const statusCounts = projects.reduce((acc, p) => { const k = p.status || 'Planning'; acc[k] = (acc[k] || 0) + 1; return acc; }, {});
  const getStatus = (s) => statusCounts[s] || 0;

  const heroStats = [
    { label: 'Total Projects', value: String(total), caption: '100%', icon: FolderKanban, tone: 'blue' },
    { label: 'Active Projects', value: String(getStatus('Active')), caption: pct(getStatus('Active')), icon: Zap, tone: 'green' },
    { label: 'Planning', value: String(getStatus('Planning')), caption: pct(getStatus('Planning')), icon: Clock3, tone: 'amber' },
    { label: 'On Hold', value: String(getStatus('On Hold')), caption: pct(getStatus('On Hold')), icon: Wrench, tone: 'purple' },
    { label: 'Completed', value: String(getStatus('Completed')), caption: pct(getStatus('Completed')), icon: CheckCircle2, tone: 'cyan' },
    { label: 'Cancelled', value: String(getStatus('Cancelled')), caption: pct(getStatus('Cancelled')), icon: AlertTriangle, tone: 'red' },
  ];

  const totalCapacity = projects.reduce((s, p) => s + Number(p.capacity_kwp || 0), 0);
  const totalValueSum = projects.reduce((s, p) => s + Number(p.total_value || 0), 0);
  const avgValue = total > 0 ? totalValueSum / total : 0;
  const inr = (n) => `₹ ${Math.round(n).toLocaleString('en-IN')}`;
  const summaryStats = [
    { label: 'Total Capacity (KWp)', value: totalCapacity.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 }), caption: `${total} projects`, icon: Zap, tone: 'green' },
    { label: 'Total Project Value (₹)', value: inr(totalValueSum), caption: 'Across all projects', icon: IndianRupee, tone: 'green' },
    { label: 'Avg. Project Value (₹)', value: inr(avgValue), caption: 'Per project', icon: BarChart3, tone: 'blue' },
    { label: 'Projects Completed', value: String(getStatus('Completed')), caption: pct(getStatus('Completed')), icon: Trophy, tone: 'amber' },
  ];

  const statusPalette = { Planning: '#f59e0b', Active: '#2f80ff', 'On Hold': '#8b5cf6', Completed: '#14b84c', Cancelled: '#ef4444' };
  const statusData = Object.keys(statusPalette)
    .map((s) => ({ label: s, value: getStatus(s), color: statusPalette[s] }))
    .filter((item) => item.value > 0);

  const cityCounts = projects.reduce((acc, p) => { const k = (p.site || p.customer_name || 'Unspecified'); acc[k] = (acc[k] || 0) + 1; return acc; }, {});
  const sitePalette = ['#2f80ff', '#14b84c', '#f59e0b', '#8b5cf6', '#ef4444'];
  const cityEntries = Object.entries(cityCounts).sort((a, b) => b[1] - a[1]);
  const otherCount = cityEntries.slice(4).reduce((s, [, v]) => s + v, 0);
  const siteData = [
    ...cityEntries.slice(0, 4).map(([label, value], i) => ({ label, value, color: sitePalette[i] })),
    ...(otherCount > 0 ? [{ label: 'Other', value: otherCount, color: sitePalette[4] }] : []),
  ];

  const now = new Date();
  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const trendMonths = Array.from({ length: 12 }, (_, i) => new Date(now.getFullYear(), now.getMonth() - (11 - i), 1));
  const monthKey = (d) => `${d.getFullYear()}-${d.getMonth()}`;
  const newByMonth = {};
  const completedByMonth = {};
  projects.forEach((p) => {
    if (p.created_at) { const d = new Date(p.created_at); newByMonth[monthKey(d)] = (newByMonth[monthKey(d)] || 0) + 1; }
    if (p.status === 'Completed' && p.target_date) { const d = new Date(p.target_date); completedByMonth[monthKey(d)] = (completedByMonth[monthKey(d)] || 0) + 1; }
  });
  const trendLabels = trendMonths.map((d) => `${monthNames[d.getMonth()]}\n${d.getFullYear()}`);
  const trendSeries = [
    { label: 'New Projects', color: '#2f80ff', values: trendMonths.map((d) => newByMonth[monthKey(d)] || 0) },
    { label: 'Completed Projects', color: '#29b36a', values: trendMonths.map((d) => completedByMonth[monthKey(d)] || 0) },
  ];

  const recentProjects = [...projects]
    .sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')))
    .slice(0, 5)
    .map((p) => ({
      id: p.id,
      name: p.project_name,
      customer: [p.customer_name, p.site].filter(Boolean).join(', ') || '—',
      capacity: Number(p.capacity_kwp || 0).toFixed(2),
      status: p.status,
      manager: p.manager_name || '—',
      startDate: p.start_date ? formatProjectDisplayDate(p.start_date) : '—',
      targetDate: p.target_date ? formatProjectDisplayDate(p.target_date) : '—',
    }));

  const todayIso = new Date().toISOString().slice(0, 10);
  const milestones = projects
    .filter((p) => p.target_date && p.target_date >= todayIso && p.status !== 'Completed' && p.status !== 'Cancelled')
    .sort((a, b) => a.target_date.localeCompare(b.target_date))
    .slice(0, 4)
    .map((p) => ({
      title: p.project_name,
      site: [p.site, p.customer_name].filter(Boolean).join(' • ') || '—',
      due: formatProjectDisplayDate(p.target_date),
      note: projectDaysLeft(p.target_date),
    }));

  const openProjectMetric = (label) => {
    const targets = {
      'Total Projects': 'Project List',
      'Active Projects': 'Project List',
      Planning: 'Project List',
      'On Hold': 'Project List',
      Completed: 'Project Reports',
      Cancelled: 'Project List',
      'Total Capacity (KWp)': 'Project KPI Analytics',
      'Total Project Value (₹)': 'Project Expenses',
      'Avg. Project Value (₹)': 'Project KPI Analytics',
      'Projects Completed': 'Project Reports',
    };
    onOpenSection(targets[label] ?? 'Project List');
  };

  return (
    <div className="space-y-4">
      <PageHeading
        title="Project Management"
        crumbs={[
          { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
          { label: 'Summary', onClick: () => onOpenSection('Project Overview') },
          { label: 'Overview' },
        ]}
        actions={(
          <>
            <div className="w-full sm:w-[280px]">
              <ReportDateRangePicker open={dateRangeOpen} onToggle={() => setDateRangeOpen((current) => !current)} onClose={() => setDateRangeOpen(false)} dateFrom={dateFrom} dateTo={dateTo} setDateFrom={setDateFrom} setDateTo={setDateTo} formattedRange={formattedRange} hideLabel />
            </div>
            <button type="button" onClick={() => onNotify(`Project overview exported for ${formattedRange}`)} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"><Download className="size-4 text-[#0b65e5]" />Export Report</button>
          </>
        )}
      />

      <SummarySubnavTabs activeSection={activeSection} onOpenSection={onOpenSection} />
      <p className="text-[14px] font-bold text-[#324871]">Track end-to-end execution, project value, installation progress and upcoming milestones across all active solar projects.</p>

      <section className="grid gap-4 sm:grid-cols-2 2xl:grid-cols-6">
        {heroStats.map((stat) => <ProjectMetricCard key={stat.label} stat={stat} onClick={() => openProjectMetric(stat.label)} />)}
      </section>

      <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        {summaryStats.map((stat) => <ProjectSummaryCard key={stat.label} stat={stat} onClick={() => openProjectMetric(stat.label)} />)}
      </section>

      <section className="grid gap-4 xl:grid-cols-[0.95fr_1.25fr_0.95fr]">
        <ProjectDonutCard title="Projects by Status" totalLabel="Total" totalValue={String(total)} data={statusData} onNotify={onNotify} />
        <ProjectLineChartCard title="Projects Trend (Monthly)" series={trendSeries} labels={trendLabels} height={244} onNotify={onNotify} />
        <ProjectDonutCard title="Projects by Site" totalLabel="Total" totalValue={String(total)} data={siteData} onNotify={onNotify} />
      </section>

      <section className="grid gap-4 xl:grid-cols-[minmax(0,1.35fr)_360px]">
        <article className={`${panelClass} overflow-hidden p-4 sm:p-5`}>
          <div className="flex items-center justify-between gap-3">
            <h2 className="font-display text-[18px] font-extrabold text-[#06135a]">Recent Projects</h2>
            <button type="button" onClick={() => onOpenSection('Project List')} className="text-[12px] font-extrabold text-[#0b65e5]">View All Projects</button>
          </div>
          <div className="mt-4 hidden overflow-x-auto rounded-[12px] border border-[#e7eef7] bg-white lg:block">
            <table className="crm-table min-w-[980px] w-full">
              <thead><tr>{['#', 'Project Name', 'Customer / Site', 'Capacity (KWp)', 'Status', 'Project Manager', 'Start Date', 'Target Date'].map((header) => <th key={header}>{header}</th>)}</tr></thead>
              <tbody>
                {recentProjects.map((row, index) => (
                  <tr key={row.id}>
                    <td>{index + 1}</td>
                    <td className="font-extrabold text-[#1e3261]">{row.name}</td>
                    <td>{row.customer}</td>
                    <td>{row.capacity}</td>
                    <td><ProjectPhaseBadge label={row.status} /></td>
                    <td>{row.manager}</td>
                    <td>{row.startDate}</td>
                    <td>{row.targetDate}</td>
                  </tr>
                ))}
                {loadingProjects ? (
                  <tr><td colSpan={8}><PageLoadingState message="Loading projects..." compact /></td></tr>
                ) : recentProjects.length === 0 ? (
                  <tr><td colSpan={8} className="py-8 text-center text-[13px] font-bold text-[#8a98af]">No projects yet.</td></tr>
                ) : null}
              </tbody>
            </table>
          </div>
          <div className="mt-4 space-y-3 lg:hidden">
            {recentProjects.map((row) => (
              <article key={row.id} className="rounded-[14px] border border-[#e7eef7] bg-white p-4 shadow-[0_10px_22px_rgba(17,39,84,0.05)]">
                <p className="text-[14px] font-extrabold text-[#1e3261]">{row.name}</p>
                <p className="mt-1 text-[12px] font-bold text-[#53647f]">{row.customer}</p>
                <div className="mt-3 grid gap-3 text-[12px] min-[420px]:grid-cols-2">
                  <InfoCell label="Capacity" value={`${row.capacity} KWp`} />
                  <InfoCell label="Status" valueNode={<ProjectPhaseBadge label={row.status} />} />
                  <InfoCell label="Project Manager" value={row.manager} />
                  <InfoCell label="Target Date" value={row.targetDate} />
                </div>
              </article>
            ))}
          </div>
        </article>

        <article className={`${panelClass} p-4 sm:p-5`}>
          <div className="flex items-center justify-between gap-3">
            <h2 className="font-display text-[18px] font-extrabold text-[#06135a]">Upcoming Milestones</h2>
            <button type="button" onClick={() => onOpenSection('Project Timeline')} className="text-[12px] font-extrabold text-[#0b65e5]">View All Milestones</button>
          </div>
          <div className="mt-5 space-y-5">
            {loadingProjects ? (
              <PageLoadingState message="Loading milestones..." compact />
            ) : milestones.length === 0 ? (
              <p className="text-[13px] font-bold text-[#8a98af]">No upcoming milestones.</p>
            ) : null}
            {!loadingProjects && milestones.map((item) => (
              <button key={item.title} type="button" onClick={() => onOpenSection('Project Timeline')} className="flex w-full items-start gap-3 rounded-[12px] border border-[#edf2f8] p-3 text-left transition hover:bg-[#f8fbff]">
                <span className="grid size-10 shrink-0 place-items-center rounded-full bg-[#eef4ff] text-[#5e83ff]"><UserRound className="size-4" /></span>
                <span className="min-w-0 flex-1">
                  <span className="block text-[13px] font-extrabold text-[#1e3261]">{item.title}</span>
                  <span className="mt-1 block text-[12px] font-bold text-[#53647f]">{item.site}</span>
                </span>
                <span className="shrink-0 text-right">
                  <span className="block text-[12px] font-extrabold text-[#314a79]">{item.due}</span>
                  <span className="mt-1 block text-[12px] font-bold text-[#53647f]">{item.note}</span>
                </span>
              </button>
            ))}
          </div>
        </article>
      </section>

      <DashboardFooter />
    </div>
  );
}

function ProjectKpiAnalyticsPage({ activeSection, onOpenSection, onNotify }) {
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const [dateFrom, setDateFrom] = useState('2026-01-01');
  const [dateTo, setDateTo] = useState('2026-12-31');
  const formattedRange = formatProjectDateRange(dateFrom, dateTo);

  const [projects, setProjects] = useState([]);

  useEffect(() => {
    let cancelled = false;
    projectApi.list({ page_size: 1000 })
      .then((res) => { if (!cancelled) setProjects(Array.isArray(res) ? res : res?.results ?? []); })
      .catch(() => { if (!cancelled) setProjects([]); });
    return () => { cancelled = true; };
  }, []);

  const total = projects.length;
  const pct = (n) => (total > 0 ? `${((n / total) * 100).toFixed(1)}%` : '0%');
  const statusCounts = projects.reduce((acc, p) => { const k = p.status || 'Planning'; acc[k] = (acc[k] || 0) + 1; return acc; }, {});
  const getStatus = (s) => statusCounts[s] || 0;
  const inr = (n) => `₹ ${Math.round(n).toLocaleString('en-IN')}`;

  const heroStats = [
    { label: 'Total Projects', value: String(total), caption: '100%', icon: FolderKanban, tone: 'blue' },
    { label: 'Active Projects', value: String(getStatus('Active')), caption: pct(getStatus('Active')), icon: Zap, tone: 'green' },
    { label: 'Planning', value: String(getStatus('Planning')), caption: pct(getStatus('Planning')), icon: Clock3, tone: 'amber' },
    { label: 'On Hold', value: String(getStatus('On Hold')), caption: pct(getStatus('On Hold')), icon: Wrench, tone: 'purple' },
    { label: 'Completed', value: String(getStatus('Completed')), caption: pct(getStatus('Completed')), icon: CheckCircle2, tone: 'cyan' },
    { label: 'Cancelled', value: String(getStatus('Cancelled')), caption: pct(getStatus('Cancelled')), icon: AlertTriangle, tone: 'red' },
  ];

  const now = new Date();
  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const trendMonths = Array.from({ length: 12 }, (_, i) => new Date(now.getFullYear(), now.getMonth() - (11 - i), 1));
  const monthKey = (d) => `${d.getFullYear()}-${d.getMonth()}`;
  const newByMonth = {};
  const completedByMonth = {};
  projects.forEach((p) => {
    if (p.created_at) { const d = new Date(p.created_at); newByMonth[monthKey(d)] = (newByMonth[monthKey(d)] || 0) + 1; }
    if (p.status === 'Completed' && p.target_date) { const d = new Date(p.target_date); completedByMonth[monthKey(d)] = (completedByMonth[monthKey(d)] || 0) + 1; }
  });
  const trendLabels = trendMonths.map((d) => `${monthNames[d.getMonth()]}\n${d.getFullYear()}`);
  const trendSeries = [
    { label: 'New Projects', color: '#2f80ff', values: trendMonths.map((d) => newByMonth[monthKey(d)] || 0) },
    { label: 'Completed Projects', color: '#29b36a', values: trendMonths.map((d) => completedByMonth[monthKey(d)] || 0) },
  ];

  const statusPalette = { Planning: '#f59e0b', Active: '#2f80ff', 'On Hold': '#8b5cf6', Completed: '#14b84c', Cancelled: '#ef4444' };
  const statusData = Object.keys(statusPalette)
    .map((s) => ({ label: s, value: getStatus(s), color: statusPalette[s] }))
    .filter((item) => item.value > 0);

  const cityCounts = projects.reduce((acc, p) => { const k = (p.site || p.customer_name || 'Unspecified'); acc[k] = (acc[k] || 0) + 1; return acc; }, {});
  const sitePalette = ['#2f80ff', '#14b84c', '#f59e0b', '#8b5cf6', '#ef4444'];
  const cityEntries = Object.entries(cityCounts).sort((a, b) => b[1] - a[1]);
  const otherCount = cityEntries.slice(4).reduce((s, [, v]) => s + v, 0);
  const siteData = [
    ...cityEntries.slice(0, 4).map(([label, value], i) => ({ label, value, color: sitePalette[i] })),
    ...(otherCount > 0 ? [{ label: 'Others', value: otherCount, color: sitePalette[4] }] : []),
  ];

  const typePalette = { 'On-Grid': '#2f80ff', Hybrid: '#8b5cf6', 'Off-Grid': '#14b84c' };
  const typeCounts = projects.reduce((acc, p) => { const k = p.project_type || 'On-Grid'; acc[k] = (acc[k] || 0) + 1; return acc; }, {});
  const typeData = Object.keys(typePalette)
    .map((t) => ({ label: t, value: typeCounts[t] || 0, color: typePalette[t] }))
    .filter((item) => item.value > 0);

  const totalValueSum = projects.reduce((s, p) => s + Number(p.total_value || 0), 0);
  const avgValue = total > 0 ? totalValueSum / total : 0;
  const avgProgress = total > 0 ? Math.round(projects.reduce((s, p) => s + Number(p.progress_percent || 0), 0) / total) : 0;
  const financialRows = [
    { label: 'Total Project Value', value: inr(totalValueSum), change: 'Across all projects', color: '#29b36a', points: [22, 30, 28, 24, 31, 33, 24, 28, 32] },
    { label: 'Avg. Project Value', value: inr(avgValue), change: 'Per project', color: '#8b5cf6', points: [18, 12, 16, 11, 15, 18, 13, 15, 18] },
    { label: 'Total Capacity (KWp)', value: projects.reduce((s, p) => s + Number(p.capacity_kwp || 0), 0).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 }), change: 'Installed + planned', color: '#f59e0b', points: [10, 14, 14, 9, 15, 18, 10, 14, 18] },
  ];
  const performanceStats = [
    { label: 'On-Time Delivery', value: '76.12%', note: '9.45% vs Last Year', icon: Clock3, tone: 'blue' },
    { label: 'Budget Performance', value: '93.25%', note: '6.21% vs Last Year', icon: IndianRupee, tone: 'green' },
    { label: 'Team Utilization', value: '68.45%', note: '7.32% vs Last Year', icon: Users, tone: 'blue' },
    { label: 'Site Visit Completion', value: '89.12%', note: '11.23% vs Last Year', icon: MapPin, tone: 'purple' },
    { label: 'Installation Efficiency', value: '71.34%', note: '8.14% vs Last Year', icon: Settings, tone: 'cyan' },
    { label: 'Client Satisfaction', value: '4.62 / 5', note: '0.45 vs Last Year', icon: Trophy, tone: 'amber' },
  ];
  const openKpiMetric = (label) => {
    const targets = {
      'Total Projects': 'Project List',
      'Active Projects': 'Project List',
      Planning: 'Project List',
      'On Hold': 'Project List',
      Completed: 'Project Reports',
      Cancelled: 'Project List',
    };
    onOpenSection(targets[label] ?? 'Project KPI Analytics');
  };

  return (
    <div className="space-y-4">
      <PageHeading
        title="Project Management - KPI Analytics"
        crumbs={[
          { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
          { label: 'Summary', onClick: () => onOpenSection('Project Overview') },
          { label: 'KPI Analytics' },
        ]}
        actions={(
          <>
            <div className="w-full sm:w-[280px]">
              <ReportDateRangePicker open={dateRangeOpen} onToggle={() => setDateRangeOpen((current) => !current)} onClose={() => setDateRangeOpen(false)} dateFrom={dateFrom} dateTo={dateTo} setDateFrom={setDateFrom} setDateTo={setDateTo} formattedRange={formattedRange} hideLabel />
            </div>
            <button type="button" onClick={() => onNotify(`Project KPI exported for ${formattedRange}`)} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"><Download className="size-4 text-[#0b65e5]" />Export Report</button>
            <button type="button" onClick={() => onNotify('Project KPI filters applied')} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"><Filter className="size-4 text-[#0b65e5]" />Apply Filter</button>
          </>
        )}
      />

      <SummarySubnavTabs activeSection={activeSection} onOpenSection={onOpenSection} />

      <section className="grid gap-4 sm:grid-cols-2 2xl:grid-cols-6">
        {heroStats.map((stat) => <ProjectMetricCard key={stat.label} stat={stat} onClick={() => openKpiMetric(stat.label)} />)}
      </section>

      <section className="grid items-start gap-4 xl:grid-cols-[1.45fr_0.95fr_0.9fr]">
        <ProjectLineChartCard title="Projects Trend (Monthly)" series={trendSeries} labels={trendLabels} height={232} onNotify={onNotify} />
        <ProjectDonutCard title="Projects by Status" totalLabel="Total" totalValue={String(total)} data={statusData} onNotify={onNotify} />
        <ProjectCompletionGauge value={avgProgress} />
      </section>

      <section className="grid items-start gap-4 xl:grid-cols-[0.95fr_0.95fr_1.25fr]">
        <ProjectDonutCard title="Projects by Site" totalLabel="Total" totalValue={String(total)} data={siteData} onNotify={onNotify} />
        <ProjectDonutCard title="Projects by Type" totalLabel="Total" totalValue={String(total)} data={typeData} onNotify={onNotify} />
        <ProjectFinancialOverview rows={financialRows} />
      </section>

      <ProjectPerformanceSummary stats={performanceStats} onNotify={onNotify} />
      <DashboardFooter />
    </div>
  );
}

const projectManagerTones = ['amber', 'blue', 'green'];

// Project ke 3-dot menu se "Download Documents" pe printable HTML banata hai (browser ke
// Save-as-PDF se PDF nikal sakte hain). row = list ka data, detail = projectApi.get() (optional).
function buildProjectDocumentHtml(row, detail) {
  const esc = (value) => String(value ?? '').replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
  const d = detail || {};
  const inr = (n) => `₹ ${Math.round(Number(n) || 0).toLocaleString('en-IN')}`;
  const fmtDate = (v) => (v ? formatProjectDisplayDate(v) : '-');
  const cfg = d.system_config || {};
  const materials = Array.isArray(d.installation_materials) ? d.installation_materials : [];
  const expenses = Array.isArray(d.expenses) ? d.expenses : [];
  const payments = Array.isArray(d.payments) ? d.payments : [];

  const infoRow = (label, value) => `<tr><td class="k">${esc(label)}</td><td class="v">${esc(value || '-')}</td></tr>`;
  const materialsRows = materials.length
    ? materials.map((m) => `<tr><td>${esc(m.item_name)}</td><td>${esc(m.category)}</td><td>${esc(m.required_qty)} ${esc(m.unit)}</td><td>${esc(m.status)}</td></tr>`).join('')
    : '<tr><td colspan="4" class="empty">No material records</td></tr>';

  return `<!doctype html><html><head><meta charset="utf-8"><title>${esc(row.projectName)} — Project Document</title>
  <style>
    *{box-sizing:border-box;font-family:Arial,Helvetica,sans-serif;}
    body{margin:0;padding:32px;color:#1e3261;}
    .head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #11a650;padding-bottom:14px;margin-bottom:18px;}
    .brand{font-size:22px;font-weight:800;color:#11a650;}
    .brand small{display:block;font-size:11px;color:#53647f;font-weight:700;letter-spacing:.08em;}
    h1{font-size:18px;margin:0 0 2px;}
    .muted{color:#53647f;font-size:12px;}
    .grid{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:14px;}
    section{border:1px solid #e7eef7;border-radius:10px;padding:14px 16px;}
    h2{font-size:13px;margin:0 0 10px;color:#0b65e5;text-transform:uppercase;letter-spacing:.04em;}
    table{width:100%;border-collapse:collapse;font-size:12px;}
    td.k{color:#53647f;font-weight:700;padding:4px 8px 4px 0;width:46%;}
    td.v{font-weight:800;padding:4px 0;}
    table.list td,table.list th{border-bottom:1px solid #eef2f8;padding:6px 8px;text-align:left;font-size:12px;}
    table.list th{color:#53647f;font-weight:800;background:#f7faff;}
    .empty{color:#8a98af;text-align:center;}
    .full{grid-column:1 / -1;}
    .foot{margin-top:26px;font-size:11px;color:#8a98af;text-align:center;border-top:1px solid #e7eef7;padding-top:12px;}
    @media print{body{padding:14px;}}
  </style></head><body>
  <div class="head">
    <div><div class="brand">Malwa Solar Energy<small>CRM SYSTEM</small></div></div>
    <div style="text-align:right"><h1>${esc(row.projectName)}</h1><div class="muted">${esc(row.projectId || d.project_id || '')} • Status: ${esc(row.status)}</div><div class="muted">Generated: ${esc(new Date().toLocaleString('en-IN'))}</div></div>
  </div>
  <div class="grid">
    <section><h2>Customer & Site</h2><table>
      ${infoRow('Customer', row.customer)}
      ${infoRow('Mobile', row.mobile)}
      ${infoRow('IVRS No.', row.ivrs)}
      ${infoRow('Site', row.site || d.site_address)}
      ${infoRow('City / State', [d.city, d.state].filter(Boolean).join(', '))}
    </table></section>
    <section><h2>Project</h2><table>
      ${infoRow('Project Type', row.type)}
      ${infoRow('Capacity (KWp)', row.capacity)}
      ${infoRow('Manager', row.manager?.name)}
      ${infoRow('Start Date', fmtDate(row.startDate))}
      ${infoRow('Target Date', fmtDate(row.targetDate))}
      ${infoRow('Progress', `${row.progress || 0}%`)}
    </table></section>
    <section><h2>System Configuration</h2><table>
      ${infoRow('Panel', [cfg.panel_brand, cfg.panel_model].filter(Boolean).join(' '))}
      ${infoRow('Panel Wattage', cfg.panel_wattage_w ? `${cfg.panel_wattage_w} W` : '')}
      ${infoRow('Panel Count', cfg.panel_count)}
      ${infoRow('Inverter', [cfg.inverter_brand, cfg.inverter_model].filter(Boolean).join(' '))}
      ${infoRow('Inverter Capacity', cfg.inverter_capacity_kw ? `${cfg.inverter_capacity_kw} kW` : '')}
    </table></section>
    <section><h2>Financials</h2><table>
      ${infoRow('Total Value', inr(d.total_value))}
      ${infoRow('Total Expense', inr(d.total_expense))}
      ${infoRow('Total Paid', inr(d.total_paid))}
      ${infoRow('Balance', inr((Number(d.total_value) || 0) - (Number(d.total_paid) || 0)))}
      ${infoRow('Payments Recorded', payments.length)}
      ${infoRow('Expense Entries', expenses.length)}
    </table></section>
    <section class="full"><h2>Material Details</h2>
      <table class="list"><thead><tr><th>Item</th><th>Category</th><th>Quantity</th><th>Status</th></tr></thead>
      <tbody>${materialsRows}</tbody></table>
    </section>
  </div>
  <div class="foot">This document is system-generated by Malwa Solar Energy CRM.</div>
  </body></html>`;
}

// Site Survey "View" popup ke Print button se poora survey — overview, roof/electrical,
// system, financials, progress, team, documents, checklist, activities, notes — print karta hai.
function buildSiteSurveyViewHtml(row, detail) {
  const esc = (value) => String(value ?? '').replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
  const d = detail || {};
  const inr = (n) => `₹ ${Math.round(Number(n) || 0).toLocaleString('en-IN')}`;
  const fmtDate = (v) => (v ? formatProjectDisplayDate(v) : '-');
  const survey = d.site_survey || {};
  const cfg = d.system_config || {};
  const payments = Array.isArray(d.payments) ? d.payments : [];
  const expenses = Array.isArray(d.expenses) ? d.expenses : [];
  const team = Array.isArray(d.team_members) ? d.team_members : [];
  const documents = Array.isArray(d.documents) ? d.documents : [];
  const checklist = (Array.isArray(d.checklist_items) ? d.checklist_items : []).filter((c) => c.phase === 'Site Survey');
  const activities = Array.isArray(d.activities) ? d.activities : [];
  const notes = Array.isArray(d.notes) ? d.notes : [];
  const milestones = (d.milestones || []).flatMap((m) => [m, ...(m.children || [])]);
  const totalValue = Number(d.total_value || 0);
  const totalPaid = Number(d.total_paid || 0);
  const totalExpense = Number(d.total_expense || 0);

  const infoRow = (label, value) => `<tr><td class="k">${esc(label)}</td><td class="v">${esc(value || '-')}</td></tr>`;
  const kvPairs = (rows) => (Array.isArray(rows) && rows.length
    ? rows.map(([label, value]) => infoRow(label, value)).join('')
    : '<tr><td colspan="2" class="empty">No data recorded</td></tr>');
  const listTable = (headers, rows) => `<table class="list"><thead><tr>${headers.map((h) => `<th>${esc(h)}</th>`).join('')}</tr></thead><tbody>${
    rows.length ? rows.join('') : `<tr><td colspan="${headers.length}" class="empty">No records</td></tr>`
  }</tbody></table>`;

  const paymentsRows = payments.map((p) => `<tr><td>${esc(fmtDate(p.payment_date))}</td><td>${esc(inr(p.amount))}</td><td>${esc(p.payment_mode)}</td><td>${esc(p.reference || '-')}</td><td>${esc(p.created_by_name || '-')}</td></tr>`);
  const expensesRows = expenses.map((e) => `<tr><td>${esc(e.category)}</td><td>${esc(e.description)}</td><td>${esc(fmtDate(e.date))}</td><td>${esc(inr(e.amount))}</td><td>${esc(e.created_by_name || '-')}</td></tr>`);
  const teamRows = team.map((m) => `<tr><td>${esc(m.user_name)}</td><td>${esc(m.role_title || 'Member')}</td><td>${esc(m.access_level_display || '-')}</td><td>${esc(m.user_email || '-')}</td><td>${esc(m.user_mobile || '-')}</td></tr>`);
  const documentsRows = documents.map((doc) => `<tr><td>${esc(doc.name)}</td><td>${esc(doc.category || '-')}</td><td>${esc(doc.uploaded_by_name || '-')}</td><td>${esc(fmtDate(doc.uploaded_at?.slice(0, 10)))}</td></tr>`);
  const checklistRows = checklist.map((c) => `<tr><td>${esc(c.category || 'General')}</td><td>${esc(c.label)}</td><td>${c.is_checked ? 'Done' : 'Pending'}</td><td>${esc(c.notes || '-')}</td></tr>`);
  const activitiesRows = activities.map((a) => `<tr><td>${esc(a.title)}</td><td>${esc(a.activity_type)}</td><td>${esc(a.assigned_to_name || 'Unassigned')}</td><td>${esc(fmtDate(a.due_date))}</td><td>${esc(a.status)}</td></tr>`);
  const milestonesRows = milestones.map((m) => `<tr><td>${esc(m.title)}</td><td>${esc(m.category || '-')}</td><td>${esc(fmtDate(m.start_date))}</td><td>${esc(fmtDate(m.end_date))}</td><td>${esc(m.status)}</td><td>${esc(m.progress_percent)}%</td><td>${esc(m.owner_name || 'Unassigned')}</td></tr>`);
  const notesRows = notes.map((n) => `<tr><td>${esc(n.title || 'Untitled')}</td><td>${esc(n.content)}</td><td>${esc(n.created_by_name || '-')}</td><td>${esc(fmtDate(n.created_at?.slice(0, 10)))}</td><td>${n.is_pinned ? 'Yes' : 'No'}</td></tr>`);

  return `<!doctype html><html><head><meta charset="utf-8"><title>${esc(row.projectName)} — Site Survey</title>
  <style>
    *{box-sizing:border-box;font-family:Arial,Helvetica,sans-serif;}
    body{margin:0;padding:28px;color:#1e3261;}
    .head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #11a650;padding-bottom:14px;margin-bottom:18px;}
    .brand{font-size:22px;font-weight:800;color:#11a650;}
    .brand small{display:block;font-size:11px;color:#53647f;font-weight:700;letter-spacing:.08em;}
    h1{font-size:18px;margin:0 0 2px;}
    .muted{color:#53647f;font-size:12px;}
    h2.section-title{font-size:14px;margin:26px 0 10px;color:#0b65e5;text-transform:uppercase;letter-spacing:.04em;border-bottom:1px solid #e7eef7;padding-bottom:6px;}
    h2.section-title:first-of-type{margin-top:0;}
    .grid{display:grid;grid-template-columns:1fr 1fr;gap:18px;}
    section{border:1px solid #e7eef7;border-radius:10px;padding:14px 16px;}
    table{width:100%;border-collapse:collapse;font-size:12px;}
    td.k{color:#53647f;font-weight:700;padding:4px 8px 4px 0;width:46%;}
    td.v{font-weight:800;padding:4px 0;}
    table.list td,table.list th{border-bottom:1px solid #eef2f8;padding:6px 8px;text-align:left;font-size:11.5px;}
    table.list th{color:#53647f;font-weight:800;background:#f7faff;}
    .empty{color:#8a98af;text-align:center;}
    .full{grid-column:1 / -1;}
    .sub{font-size:12px;margin:0 0 8px;color:#53647f;font-weight:800;}
    .foot{margin-top:26px;font-size:11px;color:#8a98af;text-align:center;border-top:1px solid #e7eef7;padding-top:12px;}
    @media print{body{padding:14px;} section{break-inside:avoid;}}
  </style></head><body>
  <div class="head">
    <div><div class="brand">Malwa Solar Energy<small>CRM SYSTEM — SITE SURVEY REPORT</small></div></div>
    <div style="text-align:right"><h1>${esc(row.projectName)}</h1><div class="muted">${esc(row.projectId || d.project_id || '')} • Survey ${esc(survey.survey_id || '-')}</div><div class="muted">Generated: ${esc(new Date().toLocaleString('en-IN'))}</div></div>
  </div>

  <h2 class="section-title">Overview</h2>
  <div class="grid">
    <section><table>
      ${infoRow('Customer', row.customer || d.customer_name)}
      ${infoRow('Site', row.site || d.site)}
      ${infoRow('Status', d.status)}
      ${infoRow('Project Type', d.project_type)}
      ${infoRow('Capacity (kWp)', d.capacity_kwp)}
      ${infoRow('Progress', `${d.progress_percent || 0}%`)}
    </table></section>
    <section><table>
      ${infoRow('Survey Status', survey.status)}
      ${infoRow('Survey Date', fmtDate(survey.survey_date))}
      ${infoRow('Surveyed By', survey.surveyed_by_name)}
      ${infoRow('Feasibility', survey.feasibility)}
      ${infoRow('Meter No.', d.meter_number)}
      ${infoRow('Size', d.site_size)}
    </table></section>
  </div>

  <h2 class="section-title">Customer &amp; Site</h2>
  <div class="grid">
    <section><table>
      ${infoRow('Customer Name', d.customer_name)}
      ${infoRow('Site', d.site)}
      ${infoRow('Site Address', d.site_address)}
      ${infoRow('City / State', [d.city, d.state].filter(Boolean).join(', '))}
      ${infoRow('Meter No.', d.meter_number)}
      ${infoRow('Size', d.site_size)}
    </table></section>
    <section><table>${kvPairs(survey.site_details)}</table></section>
  </div>

  <h2 class="section-title">Roof &amp; Electrical</h2>
  <div class="grid">
    <section><table>
      ${infoRow('Building Type', survey.building_type)}
      ${infoRow('Floor Count', survey.floor_count)}
      ${infoRow('Roof Type', survey.roof_type)}
      ${(survey.roof_stats || []).map((s) => infoRow(s.label, s.value)).join('')}
    </table></section>
    <section><table>${kvPairs(survey.roof_details)}</table></section>
  </div>
  <section class="full"><p class="sub">Electrical Details</p><table>${kvPairs(survey.electrical_details)}</table></section>

  <h2 class="section-title">System Details</h2>
  <div class="grid">
    <section><table>
      ${infoRow('System Type', d.system_type)}
      ${infoRow('Inverter', [cfg.inverter_brand, cfg.inverter_model].filter(Boolean).join(' '))}
      ${infoRow('Inverter Capacity', cfg.inverter_capacity_kw ? `${cfg.inverter_capacity_kw} kW` : '')}
      ${infoRow('String Count', cfg.string_count)}
    </table></section>
    <section><table>
      ${infoRow('Panel', [cfg.panel_brand, cfg.panel_model].filter(Boolean).join(' '))}
      ${infoRow('Panel Wattage', cfg.panel_wattage_w ? `${cfg.panel_wattage_w} W` : '')}
      ${infoRow('Panel Count', cfg.panel_count)}
      ${infoRow('Total DC Capacity', cfg.panel_wattage_w && cfg.panel_count ? `${((cfg.panel_wattage_w * cfg.panel_count) / 1000).toFixed(2)} kWp` : '')}
    </table></section>
  </div>
  <section class="full"><table>${infoRow('Protection Devices', cfg.protection_devices)}${infoRow('Notes', cfg.notes)}</table></section>

  <h2 class="section-title">Financials</h2>
  <div class="grid">
    <section><table>
      ${infoRow('Total Value', inr(totalValue))}
      ${infoRow('Amount Received', inr(totalPaid))}
      ${infoRow('Total Expenses', inr(totalExpense))}
      ${infoRow('Net Balance', inr(totalValue - totalPaid))}
    </table></section>
    <section><table>${infoRow('Payments Recorded', payments.length)}${infoRow('Expense Entries', expenses.length)}</table></section>
  </div>
  <section class="full"><p class="sub">Payments</p>${listTable(['Date', 'Amount', 'Mode', 'Reference', 'By'], paymentsRows)}</section>
  <section class="full" style="margin-top:10px;"><p class="sub">Expenses</p>${listTable(['Category', 'Description', 'Date', 'Amount', 'By'], expensesRows)}</section>

  <h2 class="section-title">Progress</h2>
  <section class="full">${listTable(['Task / Milestone', 'Category', 'Start', 'End', 'Status', 'Progress', 'Owner'], milestonesRows)}</section>

  <h2 class="section-title">Team</h2>
  <section class="full">${listTable(['Name', 'Role', 'Access Level', 'Email', 'Phone'], teamRows)}</section>

  <h2 class="section-title">Documents</h2>
  <section class="full">${listTable(['Name', 'Category', 'Uploaded By', 'Uploaded On'], documentsRows)}</section>

  <h2 class="section-title">Checklist</h2>
  <section class="full">${listTable(['Category', 'Item', 'Status', 'Notes'], checklistRows)}</section>

  <h2 class="section-title">Activities</h2>
  <section class="full">${listTable(['Title', 'Type', 'Assigned To', 'Due Date', 'Status'], activitiesRows)}</section>

  <h2 class="section-title">Notes</h2>
  <section class="full">${listTable(['Title', 'Content', 'By', 'Date', 'Pinned'], notesRows)}</section>

  <div class="foot">This document is system-generated by Malwa Solar Energy CRM.</div>
  </body></html>`;
}

// Project List ke "Export" se ek properly-formatted Excel sheet (.xls) banata hai —
// styled header, sahi PRJ IDs, readable dates, IVRS/mobile, text-format taaki numbers na bigde.
function buildProjectListSheetHtml(rows) {
  const esc = (v) => String(v ?? '').replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
  const fmtDate = (v) => (v ? formatProjectDisplayDate(v) : '-');
  const headers = ['#', 'Project ID', 'Project Name', 'Customer', 'IVRS No.', 'Mobile', 'Site', 'Project Type', 'Capacity (KWp)', 'Status', 'Project Manager', 'Start Date', 'Target Date', 'Progress %'];
  const colWidths = [36, 108, 190, 150, 96, 108, 150, 108, 92, 92, 128, 96, 96, 72];
  const headHtml = headers.map((h) => `<th>${esc(h)}</th>`).join('');
  const colgroup = colWidths.map((width) => `<col width="${width}" style="width:${width}px">`).join('');
  const bodyHtml = rows.map((row, i) => {
    const cells = [
      { value: i + 1, className: 'p' },
      { value: row.projectId || '-', className: 't' },
      { value: row.projectName, className: '' },
      { value: row.customer, className: '' },
      { value: row.ivrs || '-', className: 't' },
      { value: row.mobile || '-', className: 't' },
      { value: row.site || '-', className: '' },
      { value: row.type, className: '' },
      { value: row.capacity, className: 'n' },
      { value: row.status, className: '' },
      { value: row.manager?.name || 'Unassigned', className: '' },
      { value: fmtDate(row.startDate), className: '' },
      { value: fmtDate(row.targetDate), className: '' },
      { value: `${row.progress || 0}%`, className: 'p' },
    ];
    return `<tr>${cells.map(({ value, className }) => `<td${className ? ` class="${className}"` : ''}>${esc(value)}</td>`).join('')}</tr>`;
  }).join('');

  return `<!DOCTYPE html>
<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
<head>
<meta http-equiv="Content-Type" content="text/html; charset=utf-8">
<!--[if gte mso 9]><xml>
<x:ExcelWorkbook>
<x:ExcelWorksheets>
<x:ExcelWorksheet>
<x:Name>Project List</x:Name>
<x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions>
</x:ExcelWorksheet>
</x:ExcelWorksheets>
</x:ExcelWorkbook>
</xml><![endif]-->
<style>
  table { border-collapse: collapse; table-layout: fixed; width: 100%; }
  col { mso-width-source: userset; }
  td, th { border: 1px solid #c7d4e6; padding: 6px 10px; font-family: Calibri, Arial, sans-serif; font-size: 11pt; vertical-align: top; }
  th { background: #11a650; color: #ffffff; font-weight: bold; text-align: left; white-space: nowrap; }
  .t { mso-number-format: "\\@"; }
  .n { mso-number-format: "0.00"; }
  .p { mso-number-format: "0"; }
  .title { font-size: 15pt; font-weight: bold; color: #11a650; font-family: Calibri, Arial, sans-serif; margin-bottom: 4px; }
  .sub { font-size: 10pt; color: #555555; font-family: Calibri, Arial, sans-serif; margin-bottom: 12px; }
</style>
</head>
<body>
  <div class="title">Malwa Solar Energy — Project List</div>
  <div class="sub">Generated ${esc(new Date().toLocaleString('en-IN'))} • ${rows.length} project(s)</div>
  <table>
    <colgroup>${colgroup}</colgroup>
    <thead><tr>${headHtml}</tr></thead>
    <tbody>${bodyHtml}</tbody>
  </table>
</body>
</html>`;
}

function projectRowFromApi(p) {
  return {
    id: p.id,
    lead: p.lead,
    leadStatus: p.lead_status || '',
    ivrs: p.lead_ivrs_number || '',
    mobile: p.lead_mobile_number || '',
    projectId: p.project_id || '',
    projectName: p.project_name,
    customer: p.customer_name,
    site: p.site,
    type: p.project_type,
    capacity: p.capacity_kwp,
    status: p.status,
    manager: p.manager
      ? { name: p.manager_name || 'Unassigned', initials: p.manager_initials || '—', tone: projectManagerTones[p.manager % projectManagerTones.length] }
      : { name: 'Unassigned', initials: '—', tone: 'blue' },
    startDate: p.start_date || '',
    targetDate: p.target_date || '',
    progress: p.progress_percent || 0,
    surveyDate: p.survey_date || '',
    surveyedBy: p.surveyed_by_name || '',
    surveyFeasibility: p.survey_feasibility || '',
    surveyStatus: p.survey_status || '',
  };
}

function buildProjectMapSearchQuery({ site_address, address, city, state } = {}) {
  const line = (site_address || address || '').trim();
  const locality = [city, state].filter((part) => part && part.trim() && part.trim() !== '—').join(', ');
  return [line, locality].filter(Boolean).join(', ');
}

function openProjectAddressInMaps(parts, onNotify) {
  const query = buildProjectMapSearchQuery(parts);
  if (!query) {
    onNotify?.('No site address available for map search');
    return;
  }
  window.open(`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(query)}`, '_blank', 'noopener,noreferrer');
}

function ProjectListPage({ activeSection, onOpenSection, onSelectProject, onNotify }) {
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [query, setQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [managerFilter, setManagerFilter] = useState('All');
  const [activePage, setActivePage] = useState(1);
  const [projectRows, setProjectRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [refreshKey, setRefreshKey] = useState(0);
  const [editProject, setEditProject] = useState(null);
  const [viewSurveyRow, setViewSurveyRow] = useState(null);
  const [editSurveyRow, setEditSurveyRow] = useState(null);
  const [createOpen, setCreateOpen] = useState(false);
  const [actionMenu, setActionMenu] = useState(null);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [deleting, setDeleting] = useState(false);
  const deferredQuery = useDeferredValue(query);
  const formattedRange = formatProjectDateRange(dateFrom, dateTo);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    projectApi.list({ page_size: 1000 })
      .then((data) => {
        if (cancelled) return;
        const list = Array.isArray(data) ? data : data?.results ?? [];
        // Project List sirf un projects ko dikhata hai jinka linked lead "Won" hai
        const wonOnly = list.filter((p) => p.lead_status === 'Won');
        setProjectRows(wonOnly.map(projectRowFromApi));
      })
      .catch(() => { if (!cancelled) setProjectRows([]); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [refreshKey]);

  const isSiteSurveyPicker = activeSection === 'Project Site Survey';

  const handleOpenProject = (row) => {
    onSelectProject?.({ id: row.id });
  };

  const handleEditProject = (row) => {
    setEditProject({ projectId: row.id, leadId: row.lead, status: row.status });
  };

  // Site Survey list: View opens a read-only popup; Edit opens the full survey hub in a popup too.
  const handleViewRow = (row) => {
    if (isSiteSurveyPicker) {
      setViewSurveyRow(row);
      return;
    }
    handleOpenProject(row);
  };

  const handleEditRow = (row) => {
    if (isSiteSurveyPicker) {
      setEditSurveyRow(row);
      return;
    }
    handleEditProject(row);
  };

  const openActionMenu = (event, row) => {
    const rect = event.currentTarget.getBoundingClientRect();
    setActionMenu({ row, x: rect.right, top: rect.bottom, anchorTop: rect.top });
  };

  const handleConfirmDelete = async () => {
    if (!deleteTarget) return;
    setDeleting(true);
    try {
      await projectApi.delete(deleteTarget.id);
      onNotify(`Project "${deleteTarget.projectName}" deleted`);
      setDeleteTarget(null);
      setRefreshKey((key) => key + 1);
    } catch (err) {
      onNotify(err?.message || 'Failed to delete project');
    } finally {
      setDeleting(false);
    }
  };

  const downloadProjectPdf = async (row) => {
    onNotify(`Preparing PDF for "${row.projectName}"...`);
    let detail = null;
    try {
      detail = await projectApi.get(row.id);
    } catch {
      detail = null;
    }
    const win = window.open('', '_blank');
    if (!win) { onNotify('Allow pop-ups to download the PDF'); return; }
    win.document.write(buildProjectDocumentHtml(row, detail));
    win.document.close();
    win.focus();
    win.onload = () => { win.print(); };
    // Fallback if onload doesn't fire (already loaded)
    setTimeout(() => { try { win.print(); } catch { /* ignore */ } }, 600);
  };

  const managerOptions = useMemo(() => {
    const names = [...new Set(projectRows.map((row) => row.manager.name).filter((n) => n && n !== 'Unassigned'))].sort();
    return ['All', ...names];
  }, [projectRows]);

  const projectStatusCounts = useMemo(() => {
    const counts = { Planning: 0, Active: 0, 'On Hold': 0, Completed: 0, Cancelled: 0 };
    for (const row of projectRows) {
      if (row.status in counts) counts[row.status] += 1;
    }
    return counts;
  }, [projectRows]);

  const filteredRows = useMemo(() => {
    const normalizedQuery = deferredQuery.trim().toLowerCase();
    return projectRows.filter((row) => {
      if (normalizedQuery) {
        const haystack = [row.projectName, row.projectId, row.customer, row.site, row.manager.name, row.ivrs, row.mobile].join(' ').toLowerCase();
        if (!haystack.includes(normalizedQuery)) return false;
      }
      if (statusFilter !== 'All') {
        const compareValue = isSiteSurveyPicker ? (row.surveyStatus || '') : row.status;
        if (compareValue !== statusFilter) return false;
      }
      if (managerFilter !== 'All' && row.manager.name !== managerFilter) return false;
      if (dateFrom && row.startDate && row.startDate < dateFrom) return false;
      if (dateTo && row.startDate && row.startDate > dateTo) return false;
      return true;
    });
  }, [deferredQuery, projectRows, statusFilter, managerFilter, dateFrom, dateTo]);

  const PROJECT_PAGE_SIZE = 10;
  const totalProjectPages = Math.max(1, Math.ceil(filteredRows.length / PROJECT_PAGE_SIZE));
  const pagedProjectRows = filteredRows.slice((activePage - 1) * PROJECT_PAGE_SIZE, activePage * PROJECT_PAGE_SIZE);

  useEffect(() => { setActivePage(1); }, [deferredQuery, statusFilter, managerFilter, dateFrom, dateTo]);

  const exportProjects = () => {
    if (loading) {
      onNotify('Please wait, projects are still loading');
      return;
    }
    if (!filteredRows.length) {
      onNotify('No projects available to export');
      return;
    }
    const html = buildProjectListSheetHtml(filteredRows);
    // BOM + Excel MIME -> Excel/Sheets ise styled spreadsheet ki tarah kholta hai (columns sahi)
    const blob = new Blob(['﻿' + html], { type: 'application/vnd.ms-excel;charset=utf-8' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Project_List_${new Date().toISOString().slice(0, 10)}.xls`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.setTimeout(() => URL.revokeObjectURL(link.href), 1000);
    onNotify(`${filteredRows.length} projects exported`);
  };

  const pageTitle = isSiteSurveyPicker ? 'Site Survey' : 'Project Management';
  const pageCrumbs = isSiteSurveyPicker
    ? [
        { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
        { label: 'Project Management', onClick: () => onOpenSection('Project List') },
        { label: 'Site Survey' },
      ]
    : [
        { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
        { label: 'Project Management', onClick: () => onOpenSection('Project List') },
        { label: 'Project List' },
      ];

  return (
    <div className="space-y-2.5">
      <PageHeading
        title={pageTitle}
        crumbs={pageCrumbs}
        actions={(
          <>
            <div className="w-full sm:w-[280px]">
              <ReportDateRangePicker open={dateRangeOpen} onToggle={() => setDateRangeOpen((current) => !current)} onClose={() => setDateRangeOpen(false)} dateFrom={dateFrom} dateTo={dateTo} setDateFrom={setDateFrom} setDateTo={setDateTo} formattedRange={formattedRange} hideLabel />
            </div>
            <button type="button" data-custom-export="true" disabled={loading} onClick={exportProjects} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff] disabled:cursor-not-allowed disabled:opacity-60"><Download className="size-4 text-[#0b65e5]" />Export</button>
          </>
        )}
      />

      <ProjectSubnavTabs activeSection={activeSection} onOpenSection={onOpenSection} />

      {!isSiteSurveyPicker ? (
        <section className={`${panelClass} overflow-hidden p-2 sm:p-2.5`}>
          <div className="flex flex-wrap items-center gap-2">
            {projectStatusTabs.map((tab) => {
              const Icon = tab.icon;
              const tone = projectStatusToneClasses[tab.tone];
              const isActive = statusFilter === tab.value;
              const count = tab.value === 'All'
                ? projectRows.length
                : (projectStatusCounts[tab.value] ?? 0);

              return (
                <button
                  key={tab.value}
                  type="button"
                  onClick={() => { setStatusFilter(tab.value); setActivePage(1); }}
                  className={cx(
                    'group inline-flex h-[38px] w-max shrink-0 items-center gap-2 rounded-[10px] border px-2.5 text-left shadow-[0_10px_20px_rgba(17,39,84,0.04)] transition hover:-translate-y-0.5',
                    tone.button,
                    isActive ? 'ring-2 ring-[#0b65e5] ring-offset-2 ring-offset-white' : '',
                  )}
                >
                  <span className={cx('grid size-6 shrink-0 place-items-center rounded-[7px]', tone.icon)}>
                    <Icon className="size-[13px]" />
                  </span>
                  <span className="whitespace-nowrap text-[12px] font-extrabold">{tab.label}</span>
                  <span className={cx('shrink-0 rounded-full px-2 py-0.5 text-[10px] font-extrabold', tone.count)}>{count}</span>
                </button>
              );
            })}
          </div>
        </section>
      ) : null}

      <section className={`${panelClass} p-2.5 sm:p-3`}>
        <div className={cx('grid gap-3 xl:items-center', isSiteSurveyPicker ? 'xl:grid-cols-[minmax(0,1fr)_124px_140px]' : 'xl:grid-cols-[minmax(0,1fr)_124px_160px_140px]')}>
          <label className="flex h-11 items-center gap-3 rounded-[10px] border border-[#dce6f3] bg-white px-4 transition focus-within:border-[#0b65e5] focus-within:ring-4 focus-within:ring-[#0b65e5]/10">
            <Search className="size-4 text-[#7e8fab]" />
            <input value={query} onChange={(event) => setQuery(event.target.value)} type="search" placeholder="Search by IVRS no, customer, project name, site, manager, mobile number..." className="min-w-0 flex-1 bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a9ab4]" />
          </label>
          <label className="relative flex h-11 items-center gap-2 rounded-[10px] border border-[#dce6f3] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]">
            <Filter className="size-4 text-[#0b65e5]" />
            <select value={statusFilter} onChange={(event) => setStatusFilter(event.target.value)} className="min-w-0 flex-1 cursor-pointer appearance-none bg-transparent text-[13px] font-extrabold text-[#284276] outline-none">
              <option value="All">All Status</option>
              {isSiteSurveyPicker ? (
                <>
                  <option value="Draft">Draft</option>
                  <option value="Completed">Completed</option>
                </>
              ) : (
                <>
                  <option value="Planning">Planning</option>
                  <option value="Active">Active</option>
                  <option value="On Hold">On Hold</option>
                  <option value="Completed">Completed</option>
                  <option value="Cancelled">Cancelled</option>
                </>
              )}
            </select>
          </label>
          {!isSiteSurveyPicker ? (
            <label className="relative flex h-11 items-center gap-2 rounded-[10px] border border-[#dce6f3] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]">
              <UserRound className="size-4 shrink-0 text-[#0b65e5]" />
              <select value={managerFilter} onChange={(event) => setManagerFilter(event.target.value)} aria-label="Assigned Manager" className="min-w-0 flex-1 cursor-pointer appearance-none bg-transparent text-[13px] font-extrabold text-[#284276] outline-none">
                <option value="All">All Managers</option>
                {managerOptions.filter((name) => name !== 'All').map((name) => (
                  <option key={name} value={name}>{name}</option>
                ))}
              </select>
            </label>
          ) : null}
          {!isSiteSurveyPicker ? (
            <button type="button" onClick={() => setCreateOpen(true)} className="inline-flex h-11 items-center justify-center gap-2 rounded-[10px] bg-[#11a650] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(17,166,80,0.22)] transition hover:-translate-y-0.5 hover:bg-[#0e9748]"><Plus className="size-4" />Add Project</button>
          ) : null}
        </div>
      </section>

      <article className={`${panelClass} overflow-hidden p-2 sm:p-2.5`}>
        {loading ? (
          <PageLoadingState message="Loading projects..." />
        ) : (
        <>
        <div className="hidden overflow-x-auto rounded-[14px] border border-[#e7eef7] bg-white lg:block">
          <table className={cx('crm-table w-full', isSiteSurveyPicker ? 'min-w-[1180px]' : 'min-w-[1420px]')}>
            <thead>
              <tr>
                {(isSiteSurveyPicker
                  ? ['#', 'Project Name', 'Customer / Site', 'Survey Status', 'Survey Date', 'Surveyed By', 'Feasibility', 'Project Manager', 'Action']
                  : ['#', 'Project Name', 'Customer / Site', 'Project Type', 'Capacity (KWp)', 'Status', 'Project Manager', 'Start Date', 'Target Date', 'Progress', 'Action']
                ).map((header) => <th key={header}>{header}</th>)}
              </tr>
            </thead>
            <tbody>
              {pagedProjectRows.map((row, index) => (
                <tr key={row.id}>
                  <td>{(activePage - 1) * PROJECT_PAGE_SIZE + index + 1}</td>
                  <td className="font-extrabold text-[#1e3261]">{row.projectName}</td>
                  <td>
                    <div className="space-y-1">
                      <p className="font-extrabold text-[#1e3261]">{row.customer}</p>
                      <p className="text-[12px] font-bold text-[#667794]">{row.site}</p>
                    </div>
                  </td>
                  {isSiteSurveyPicker ? (
                    <>
                      <td><ProjectInfoPill tone={row.surveyStatus === 'Completed' ? 'green' : 'amber'}>{row.surveyStatus || 'Not Started'}</ProjectInfoPill></td>
                      <td className="font-extrabold text-[#1e3261]">{row.surveyDate ? formatProjectDisplayDate(row.surveyDate) : '—'}</td>
                      <td>{row.surveyedBy || 'Unassigned'}</td>
                      <td><ProjectInfoPill tone={row.surveyFeasibility === 'Feasible' ? 'green' : row.surveyFeasibility === 'Not Feasible' ? 'red' : row.surveyFeasibility ? 'amber' : 'slate'}>{row.surveyFeasibility || 'Pending'}</ProjectInfoPill></td>
                      <td><AssigneeCell assignee={row.manager} compact /></td>
                    </>
                  ) : (
                    <>
                      <td><ProjectTypeBadge type={row.type} /></td>
                      <td className="font-extrabold text-[#1e3261]">{row.capacity}</td>
                      <td><ProjectPhaseBadge label={row.status} /></td>
                      <td><AssigneeCell assignee={row.manager} compact /></td>
                      <td><span className="inline-flex items-center gap-2 font-bold text-[#314a79]"><CalendarDays className="size-4 text-[#7b8ca8]" />{formatProjectDisplayDate(row.startDate)}</span></td>
                      <td><span className="inline-flex items-center gap-2 font-bold text-[#314a79]"><CalendarDays className="size-4 text-[#7b8ca8]" />{row.targetDate ? formatProjectDisplayDate(row.targetDate) : '-'}</span></td>
                      <td><ProjectProgressBar value={row.progress} /></td>
                    </>
                  )}
                  <td>
                    <div className="flex items-center gap-2">
                      <UserActionButton label={`View ${row.projectName}`} icon={Eye} tone="blue" onClick={() => handleViewRow(row)} />
                      <UserActionButton label={`Edit ${row.projectName}`} icon={Pencil} tone="green" onClick={() => handleEditRow(row)} />
                      <UserActionButton label={`More actions for ${row.projectName}`} icon={MoreVertical} tone="blue" onClick={(event) => openActionMenu(event, row)} />
                    </div>
                  </td>
                </tr>
              ))}
              {pagedProjectRows.length === 0 ? (
                <tr><td colSpan={isSiteSurveyPicker ? 9 : 11} className="py-8 text-center text-[13px] font-bold text-[#8a98af]">No projects found.</td></tr>
              ) : null}
            </tbody>
          </table>
        </div>

        <div className="space-y-2 lg:hidden">
          {pagedProjectRows.map((row) => (
            <article key={row.id} className="rounded-[14px] border border-[#e7eef7] bg-white p-3 shadow-[0_10px_22px_rgba(17,39,84,0.05)]">
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0">
                  <p className="truncate text-[15px] font-extrabold text-[#1e3261]">{row.projectName}</p>
                  <p className="mt-0.5 truncate text-[12px] font-bold text-[#53647f]">{row.customer} &middot; {row.site}</p>
                </div>
                {isSiteSurveyPicker ? (
                  <ProjectInfoPill tone={row.surveyStatus === 'Completed' ? 'green' : 'amber'}>{row.surveyStatus || 'Not Started'}</ProjectInfoPill>
                ) : (
                  <ProjectPhaseBadge label={row.status} />
                )}
              </div>

              {isSiteSurveyPicker ? (
                <div className="mt-3 flex flex-wrap items-center gap-2">
                  <ProjectInfoPill tone={row.surveyFeasibility === 'Feasible' ? 'green' : row.surveyFeasibility === 'Not Feasible' ? 'red' : row.surveyFeasibility ? 'amber' : 'slate'}>{row.surveyFeasibility || 'Pending'}</ProjectInfoPill>
                  <span className="text-[12px] font-extrabold text-[#314a79]">{row.surveyDate ? formatProjectDisplayDate(row.surveyDate) : 'No survey date'}</span>
                  <span className="ml-1 inline-flex min-w-0"><AssigneeCell assignee={row.manager} compact /></span>
                </div>
              ) : (
                <>
                  <div className="mt-3 flex flex-wrap items-center gap-2">
                    <ProjectTypeBadge type={row.type} />
                    <span className="text-[12px] font-extrabold text-[#314a79]">{row.capacity} KWp</span>
                    <span className="ml-1 inline-flex min-w-0"><AssigneeCell assignee={row.manager} compact /></span>
                  </div>

                  <div className="mt-3 flex items-center gap-3">
                    <div className="min-w-0 flex-1"><ProjectProgressBar value={row.progress} /></div>
                    <span className="shrink-0 text-[12px] font-bold text-[#7b8ca8]">{row.targetDate ? formatProjectDisplayDate(row.targetDate) : 'No target date'}</span>
                  </div>
                </>
              )}

              <div className="mt-3 flex gap-2">
                <button type="button" onClick={() => handleViewRow(row)} className="inline-flex h-10 flex-1 items-center justify-center gap-2 rounded-[10px] border border-[#dce6f3] bg-white text-[12px] font-extrabold text-[#0b65e5]"><Eye className="size-4" />View</button>
                <button type="button" onClick={() => handleEditRow(row)} className="inline-flex h-10 flex-1 items-center justify-center gap-2 rounded-[10px] border border-[#dce6f3] bg-white text-[12px] font-extrabold text-[#0d9f4a]"><Pencil className="size-4" />Edit</button>
                <button type="button" onClick={(event) => openActionMenu(event, row)} className="inline-flex h-10 w-10 items-center justify-center rounded-[10px] border border-[#dce6f3] bg-white text-[#284276]"><MoreVertical className="size-4" /></button>
              </div>
            </article>
          ))}
          {pagedProjectRows.length === 0 ? (
            <p className="py-8 text-center text-[13px] font-bold text-[#8a98af]">No projects found.</p>
          ) : null}
        </div>

        <div className="mt-3 flex flex-col gap-3 px-1 sm:flex-row sm:items-center sm:justify-between">
          <p className="text-[13px] font-bold text-[#53647f]">Showing {filteredRows.length === 0 ? 0 : (activePage - 1) * PROJECT_PAGE_SIZE + 1} to {Math.min(activePage * PROJECT_PAGE_SIZE, filteredRows.length)} of {filteredRows.length} entries</p>
          <div className="flex flex-wrap items-center justify-end gap-2">
            <PaginationButton onClick={() => setActivePage((p) => Math.max(1, p - 1))}><ChevronLeft className="size-4" /></PaginationButton>
            {Array.from({ length: totalProjectPages }, (_, i) => i + 1).map((page) => (
              <PaginationButton key={page} active={page === activePage} onClick={() => setActivePage(page)}>{page}</PaginationButton>
            ))}
            <PaginationButton onClick={() => setActivePage((p) => Math.min(totalProjectPages, p + 1))}><ChevronRight className="size-4" /></PaginationButton>
          </div>
        </div>
        </>
        )}
      </article>

      <DashboardFooter />

      {editProject ? (
        <LeadFormModal
          mode="edit"
          lead={editProject.leadId ? { id: editProject.leadId } : null}
          projectContext={editProject}
          onClose={() => setEditProject(null)}
          onSaved={() => { setEditProject(null); setRefreshKey((key) => key + 1); }}
          onNotify={onNotify}
        />
      ) : null}

      {viewSurveyRow ? (
        <SiteSurveyViewModal
          row={viewSurveyRow}
          onClose={() => setViewSurveyRow(null)}
          onNotify={onNotify}
          onViewFullProject={() => { const id = viewSurveyRow.id; setViewSurveyRow(null); onSelectProject?.({ id }); }}
        />
      ) : null}

      {editSurveyRow ? (
        <SiteSurveyEditModal row={editSurveyRow} onClose={() => setEditSurveyRow(null)} onOpenSection={onOpenSection} onNotify={onNotify} />
      ) : null}

      {createOpen ? (
        <LeadFormModal
          projectCreate
          onClose={() => setCreateOpen(false)}
          onSaved={() => { setCreateOpen(false); setRefreshKey((key) => key + 1); }}
          onNotify={onNotify}
        />
      ) : null}

      {actionMenu ? (
        <>
          <div className="fixed inset-0 z-90" onMouseDown={() => setActionMenu(null)} />
          <div
            className="fixed z-95 w-[206px] overflow-hidden rounded-[12px] border border-[#dce7f5] bg-white py-1 shadow-[0_18px_34px_rgba(21,43,83,0.16)]"
            style={(() => {
              const flipUp = actionMenu.top + 250 > window.innerHeight;
              return {
                left: Math.max(12, actionMenu.x - 206),
                top: flipUp ? undefined : actionMenu.top + 6,
                bottom: flipUp ? Math.max(12, window.innerHeight - actionMenu.anchorTop + 6) : undefined,
              };
            })()}
          >
            <button
              type="button"
              onClick={() => { const row = actionMenu.row; setActionMenu(null); onSelectProject?.({ id: row.id }, 'Project Work Orders'); }}
              className="flex w-full items-center gap-2.5 px-4 py-2.5 text-left text-[12px] font-extrabold text-[#263d72] transition hover:bg-[#f5f9ff]"
            >
              <Wrench className="size-4 text-[#0b65e5]" />
              Work Orders
            </button>
            <button
              type="button"
              onClick={() => { const row = actionMenu.row; setActionMenu(null); onSelectProject?.({ id: row.id }, 'Project Report View'); }}
              className="flex w-full items-center gap-2.5 px-4 py-2.5 text-left text-[12px] font-extrabold text-[#263d72] transition hover:bg-[#f5f9ff]"
            >
              <BarChart3 className="size-4 text-[#0b65e5]" />
              Reports
            </button>
            <button
              type="button"
              onClick={() => { const row = actionMenu.row; setActionMenu(null); onSelectProject?.({ id: row.id }, 'Project Timeline'); }}
              className="flex w-full items-center gap-2.5 px-4 py-2.5 text-left text-[12px] font-extrabold text-[#263d72] transition hover:bg-[#f5f9ff]"
            >
              <CalendarDays className="size-4 text-[#0b65e5]" />
              Project Timeline
            </button>
            <button
              type="button"
              onClick={() => { const row = actionMenu.row; setActionMenu(null); downloadProjectPdf(row); }}
              className="flex w-full items-center gap-2.5 px-4 py-2.5 text-left text-[12px] font-extrabold text-[#263d72] transition hover:bg-[#f5f9ff]"
            >
              <Download className="size-4 text-[#0b65e5]" />
              Download Documents
            </button>
            <div className="my-1 border-t border-[#eef2f8]" />
            <button
              type="button"
              onClick={() => { const row = actionMenu.row; setActionMenu(null); setDeleteTarget(row); }}
              className="flex w-full items-center gap-2.5 px-4 py-2.5 text-left text-[12px] font-extrabold text-[#ef4444] transition hover:bg-[#fff5f5]"
            >
              <Trash2 className="size-4 text-[#ef4444]" />
              Delete Project
            </button>
          </div>
        </>
      ) : null}

      {deleteTarget ? (
        <div className="modal-overlay fixed inset-0 z-100 flex items-center justify-center bg-[#111827]/55 p-4" onMouseDown={(event) => { if (event.target === event.currentTarget && !deleting) setDeleteTarget(null); }}>
          <div className="modal-pop-in w-full max-w-[420px] rounded-[16px] bg-white p-6 shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
            <div className="flex items-start gap-3">
              <span className="grid size-11 shrink-0 place-items-center rounded-full bg-[#ffeceb] text-[#ef4444]"><Trash2 className="size-5" /></span>
              <div className="min-w-0">
                <h2 className="font-display text-[17px] font-extrabold text-[#111827]">Delete Project</h2>
                <p className="mt-1 text-[13px] font-bold leading-6 text-[#53647f]">Are you sure you want to delete <span className="text-[#1e3261]">{deleteTarget.projectName}</span>? This action cannot be undone and removes all related records.</p>
              </div>
            </div>
            <div className="mt-6 flex justify-end gap-3">
              <button type="button" disabled={deleting} onClick={() => setDeleteTarget(null)} className="h-11 rounded-[8px] border border-black/20 bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff] disabled:opacity-60">Cancel</button>
              <button type="button" disabled={deleting} onClick={handleConfirmDelete} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#ef4444] px-5 text-[13px] font-extrabold text-white transition hover:bg-[#dc2f2f] disabled:opacity-60">
                <Trash2 className="size-4" />
                {deleting ? 'Deleting...' : 'Delete Project'}
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
}

// Site Survey list ke "View" action ka read-only quick-look popup — sirf survey-relevant
// essentials (Survey Snapshot, Customer & Site, Roof & Electrical), Lead/Quotation view popup
// jaisa compact. Pura project data (Financials/Progress/Team/Documents/Checklist/Activities/Notes)
// "View Full Project" se full hub page par dekha ja sakta hai; Print abhi bhi poora report nikalta
// hai (buildSiteSurveyViewHtml unchanged — record-keeping ke liye full detail).
function SiteSurveyViewModal({ row, onClose, onNotify, onViewFullProject }) {
  const [detail, setDetail] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    projectApi.get(row.id)
      .then((data) => { if (!cancelled) setDetail(data); })
      .catch((err) => { if (!cancelled) onNotify(err?.message || 'Failed to load site survey details'); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [row.id]);

  const handlePrint = () => {
    const win = window.open('', '_blank');
    if (!win) { onNotify('Allow pop-ups to print this document'); return; }
    win.document.write(buildSiteSurveyViewHtml(row, detail));
    win.document.close();
    win.focus();
    win.onload = () => { win.print(); };
    setTimeout(() => { try { win.print(); } catch { /* ignore */ } }, 600);
  };

  const d = detail || {};
  const survey = d.site_survey || {};
  const feasibilityTone = survey.feasibility === 'Feasible' ? 'green' : survey.feasibility === 'Not Feasible' ? 'red' : survey.feasibility ? 'amber' : 'slate';

  return (
    <div className="fixed inset-0 z-100 flex items-center justify-center bg-[#0b1226]/55 p-4 backdrop-blur-[2px]" onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}>
      <div className="flex max-h-[92vh] w-full max-w-[760px] flex-col overflow-hidden rounded-[18px] bg-white shadow-[0_36px_80px_rgba(11,18,38,0.32)]">
        <div className="flex items-start justify-between gap-4 border-b border-[#e7eef7] px-5 py-4 sm:px-6">
          <div className="flex items-start gap-3">
            <span className="grid size-11 shrink-0 place-items-center rounded-[12px] bg-[#dff7e8] text-[#0d9f4a]"><ClipboardPlus className="size-5" /></span>
            <div className="min-w-0">
              <h2 className="font-display text-[18px] font-extrabold leading-tight text-[#06135a] sm:text-[20px]">{row.projectName}</h2>
              <p className="mt-1 text-[12px] font-bold text-[#53647f]">{row.projectId || d.project_id} • Survey {survey.survey_id || 'Not yet created'} • {row.customer}</p>
            </div>
          </div>
          <button type="button" onClick={onClose} className="grid size-9 shrink-0 place-items-center rounded-[8px] text-[#7585a2] transition hover:bg-[#f1f5fa]" aria-label="Close site survey details">
            <X className="size-5" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto px-5 py-5 sm:px-6">
          {loading ? (
            <PageLoadingState message="Loading site survey details..." />
          ) : (
            <div className="space-y-5">
              <ProjectInfoCard title="Survey Snapshot" icon={Home} tone="blue">
                <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
                  <InfoCell label="Project Status" valueNode={<ProjectPhaseBadge label={d.status} />} />
                  <InfoCell label="Survey Status" value={survey.status || 'Draft'} />
                  <InfoCell label="Survey ID" value={survey.survey_id || '—'} />
                  <InfoCell label="Survey Date" value={survey.survey_date ? formatProjectDisplayDate(survey.survey_date) : '—'} />
                  <InfoCell label="Surveyed By" value={survey.surveyed_by_name || 'Unassigned'} />
                  <InfoCell label="Feasibility" valueNode={<ProjectInfoPill tone={feasibilityTone}>{survey.feasibility || 'Pending'}</ProjectInfoPill>} />
                  <InfoCell label="Manager" value={d.manager_detail?.name || 'Unassigned'} />
                  <InfoCell label="Site Engineer" value={d.site_engineer_detail?.name || 'Unassigned'} />
                </div>
              </ProjectInfoCard>

              <ProjectInfoCard title="Customer & Site" icon={MapPin} tone="blue">
                <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                  <InfoCell label="Customer Name" value={d.customer_name || '—'} />
                  <InfoCell label="Site" value={d.site || '—'} />
                  <InfoCell label="Meter No." value={d.meter_number || '—'} />
                  <InfoCell label="Size" value={d.site_size || '—'} />
                  <InfoCell label="City" value={d.city || '—'} />
                  <InfoCell label="State" value={d.state || '—'} />
                </div>
                <div className="mt-4 border-t border-[#edf2f8] pt-4">
                  <InfoCell label="Site Address" value={d.site_address || '—'} large />
                </div>
                {survey.site_details?.length ? (
                  <div className="mt-4 border-t border-[#edf2f8] pt-4">
                    <p className="mb-3 text-[12px] font-extrabold uppercase tracking-wide text-[#7386a3]">Site Condition Details</p>
                    <div className="grid gap-3 sm:grid-cols-2">
                      {survey.site_details.map(([label, value]) => (
                        <div key={label} className="grid gap-1 text-[13px] sm:grid-cols-[160px_1fr]">
                          <span className="font-bold text-[#53647f]">{label}</span>
                          <span className="font-extrabold text-[#1e3261]">{value}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                ) : null}
                {survey.summary_notes ? (
                  <div className="mt-4 border-t border-[#edf2f8] pt-4">
                    <p className="mb-2 text-[12px] font-extrabold uppercase tracking-wide text-[#7386a3]">Survey Summary</p>
                    <p className="text-[13px] font-bold leading-6 text-[#314a79]">{survey.summary_notes}</p>
                  </div>
                ) : null}
              </ProjectInfoCard>

              <ProjectInfoCard title="Roof & Electrical" icon={Zap} tone="amber">
                <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
                  <InfoCell label="Building Type" value={survey.building_type || '—'} />
                  <InfoCell label="Floor Count" value={survey.floor_count || '—'} />
                  <InfoCell label="Roof Type" value={survey.roof_type || '—'} />
                  {(survey.roof_stats || []).map((stat) => (
                    <InfoCell key={stat.label} label={stat.label} value={stat.value ?? '—'} />
                  ))}
                </div>
                <div className="mt-5 grid gap-4 border-t border-[#edf2f8] pt-4 sm:grid-cols-2">
                  <div>
                    <p className="mb-3 text-[12px] font-extrabold uppercase tracking-wide text-[#7386a3]">Roof Measurements</p>
                    <div className="space-y-2">
                      {(survey.roof_details || []).length ? survey.roof_details.map(([label, value]) => (
                        <div key={label} className="grid gap-1 text-[13px] sm:grid-cols-[150px_1fr]">
                          <span className="font-bold text-[#53647f]">{label}</span>
                          <span className="font-extrabold text-[#1e3261]">{value}</span>
                        </div>
                      )) : <p className="text-[13px] font-bold text-[#8a98af]">No roof details recorded yet.</p>}
                    </div>
                  </div>
                  <div>
                    <p className="mb-3 text-[12px] font-extrabold uppercase tracking-wide text-[#7386a3]">Electrical Details</p>
                    <div className="space-y-2">
                      {(survey.electrical_details || []).length ? survey.electrical_details.map(([label, value]) => (
                        <div key={label} className="grid gap-1 text-[13px] sm:grid-cols-[150px_1fr]">
                          <span className="font-bold text-[#53647f]">{label}</span>
                          <span className="font-extrabold text-[#1e3261]">{value}</span>
                        </div>
                      )) : <p className="text-[13px] font-bold text-[#8a98af]">No electrical details recorded yet.</p>}
                    </div>
                  </div>
                </div>
              </ProjectInfoCard>

            </div>
          )}
        </div>

        <div className="flex flex-col-reverse gap-3 border-t border-[#e7eef7] px-5 py-4 sm:flex-row sm:items-center sm:justify-end sm:px-6">
          <button type="button" onClick={onClose} className="inline-flex h-11 items-center justify-center rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#53647f] transition hover:bg-[#f8fbff]">Close</button>
          {onViewFullProject ? (
            <button type="button" onClick={onViewFullProject} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#0b65e5] transition hover:bg-[#f8fbff]">
              <FolderKanban className="size-4" />
              View Full Project
            </button>
          ) : null}
          <button type="button" disabled={loading} onClick={handlePrint} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#0d9f4a] px-6 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(13,159,74,0.22)] transition hover:bg-[#078c3e] disabled:cursor-not-allowed disabled:opacity-60">
            <Printer className="size-4" />
            Print
          </button>
        </div>
      </div>
    </div>
  );
}

// Office-wide view across every project's site survey — counts by status,
// engineer-wise breakdown, and a one-click "View" into the same edit popup
// used from Project Management.
function SurveyDashboardPage({ onNotify }) {
  const [summary, setSummary] = useState(null);
  const [surveys, setSurveys] = useState([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('All');
  const [viewSurveyRow, setViewSurveyRow] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);

  useEffect(() => {
    setLoading(true);
    Promise.all([
      siteSurveyApi.summary(),
      siteSurveyApi.list(statusFilter !== 'All' ? { status: statusFilter } : {}),
    ]).then(([summaryData, listData]) => {
      setSummary(summaryData);
      setSurveys(Array.isArray(listData) ? listData : (listData?.results ?? []));
    }).catch(() => {
      onNotify?.('Failed to load survey dashboard', 'error');
    }).finally(() => setLoading(false));
  }, [statusFilter, refreshKey, onNotify]);

  const stats = [
    { label: 'Total Surveys', value: summary?.total ?? '—', toneClass: 'bg-linear-to-br from-[#1578ff] to-[#0a9ff5]', icon: ClipboardPlus },
    { label: 'Pending', value: summary?.pending ?? '—', toneClass: 'bg-linear-to-br from-[#ef4444] to-[#f87171]', icon: Clock3 },
    { label: 'In Progress', value: summary?.in_progress ?? '—', toneClass: 'bg-linear-to-br from-[#f59e0b] to-[#fb923c]', icon: RefreshCw },
    { label: 'Completed', value: summary?.completed ?? '—', toneClass: 'bg-linear-to-br from-[#10b981] to-[#059669]', icon: CheckCircle2 },
  ];

  return (
    <div className="space-y-4">
      <Card className="p-4">
        <h2 className="font-display text-[18px] font-extrabold text-[#111827]">Survey Dashboard</h2>
        <p className="mt-1 text-[12px] font-bold text-[#7386a3]">Office-wide view of every site survey across all projects.</p>
      </Card>

      <section className="grid grid-cols-[repeat(auto-fit,minmax(160px,1fr))] gap-3">
        {stats.map((stat) => {
          const Icon = stat.icon;
          return (
            <article key={stat.label} className={`${panelClass} flex items-center gap-3 p-4`}>
              <span className={cx('grid size-11 shrink-0 place-items-center rounded-full text-white', stat.toneClass)}>
                <Icon className="size-5" />
              </span>
              <div className="min-w-0">
                <p className="text-[11px] font-extrabold uppercase text-[#7b88a2]">{stat.label}</p>
                <p className="font-display text-[21px] font-extrabold text-[#223768]">{stat.value}</p>
              </div>
            </article>
          );
        })}
      </section>

      {summary?.engineer_stats?.length ? (
        <article className={dataPanelClass}>
          <SectionHeader icon={UserRound} title="Survey Engineer-wise Status" />
          <div className="overflow-x-auto p-4">
            <table className="crm-table min-w-[520px] w-full">
              <thead>
                <tr><th>Engineer</th><th>Total</th><th>Pending</th><th>In Progress</th><th>Completed</th></tr>
              </thead>
              <tbody>
                {summary.engineer_stats.map((row) => (
                  <tr key={row.name}>
                    <td className="font-bold text-[#233a6b]">{row.name}</td>
                    <td>{row.total}</td>
                    <td>{row.pending}</td>
                    <td>{row.in_progress}</td>
                    <td>{row.completed}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </article>
      ) : null}

      <article className={dataPanelClass}>
        <SectionHeader icon={ClipboardPlus} title="All Surveys" />
        <div className="flex flex-wrap items-center gap-2 border-b border-[#e5edf6] px-4 py-3">
          {['All', 'Pending', 'In Progress', 'Completed'].map((s) => (
            <button
              key={s}
              type="button"
              onClick={() => setStatusFilter(s)}
              className={cx(
                'rounded-full px-3 py-1.5 text-[12px] font-extrabold transition',
                statusFilter === s ? 'bg-[#0b65e5] text-white' : 'border border-[#d4d9e7] bg-white text-[#324f7b] hover:bg-[#f4f7ff]',
              )}
            >
              {s}
            </button>
          ))}
        </div>
        {loading ? (
          <PageLoadingState message="Loading surveys..." />
        ) : surveys.length === 0 ? (
          <p className="py-12 text-center text-[13px] font-bold text-[#7386a3]">No surveys found</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="crm-table min-w-[820px] w-full">
              <thead>
                <tr>
                  <th>Survey Date</th><th>Project</th><th>Customer</th><th>Engineer</th><th>Status</th><th>Completion</th><th className="text-right">Action</th>
                </tr>
              </thead>
              <tbody>
                {surveys.map((row) => (
                  <tr key={row.id}>
                    <td>{row.survey_date ? new Date(row.survey_date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : '—'}</td>
                    <td className="font-bold text-[#233a6b]">{row.project_name || '—'}</td>
                    <td>{row.customer_name || '—'}</td>
                    <td>{row.surveyed_by_name || 'Unassigned'}</td>
                    <td><SurveyStatusBadge status={row.status} /></td>
                    <td>
                      <div className="flex items-center gap-2">
                        <div className="h-1.5 w-16 overflow-hidden rounded-full bg-[#e7eef7]">
                          <div className="h-full rounded-full bg-[#0b65e5]" style={{ width: `${row.completion_percent}%` }} />
                        </div>
                        <span className="text-[11px] font-extrabold text-[#4b5b78]">{row.completion_percent}%</span>
                      </div>
                    </td>
                    <td className="text-right">
                      <button
                        type="button"
                        onClick={() => setViewSurveyRow({ id: row.project })}
                        className="inline-flex size-8 items-center justify-center rounded-[8px] border border-[#e3ebf7] bg-white text-[#3480ff] transition hover:bg-[#f5f9ff]"
                        aria-label={`View survey for ${row.project_name}`}
                      >
                        <Eye className="size-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </article>

      {viewSurveyRow ? (
        <SiteSurveyEditModal
          row={viewSurveyRow}
          onClose={() => { setViewSurveyRow(null); setRefreshKey((k) => k + 1); }}
          onNotify={onNotify}
        />
      ) : null}
    </div>
  );
}

// Site Survey list ke "Edit" action ka popup — poora 12-section survey form
// (Survey Info, Roof Details, Roof Photo Checklist, Earthing, Inverter Location,
// Meter, Cable Route, Structure Layout, Safety Checklist, Documents, Remarks,
// Completion) ek modal ke andar, alag page par navigate kiye bina.
function SiteSurveyEditModal({ row, onClose, onOpenSection, onNotify }) {
  return (
    <div
      className="modal-overlay fixed inset-0 z-100 flex items-center justify-center bg-[#111827]/55 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex max-h-[92vh] w-full max-w-[960px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <SiteSurveyFullForm projectId={row.id} onClose={onClose} onNotify={onNotify} />
      </div>
    </div>
  );
}

