    green: 'border-[#d8efdf] bg-[#f3fff6] text-[#0d9f4a]',
    blue: 'border-[#d9e9ff] bg-[#f5f9ff] text-[#0b65e5]',
    amber: 'border-[#f8e1b4] bg-[#fff8eb] text-[#d98200]',
    purple: 'border-[#e5ddff] bg-[#fbf8ff] text-[#7c3aed]',
