function AccessBadge({ access }) {
  const classes = access === 'Full Access' ? 'bg-[#e8f8eb] text-[#0d9f4a]' : 'bg-[#e8f2ff] text-[#0b65e5]';
  return <span className={cx('inline-flex rounded-[7px] px-2.5 py-1 text-[11px] font-extrabold', classes)}>{access}</span>;
}

const PERMISSION_ACTION_FIELDS = [
  ['View', 'can_view'],
  ['Add', 'can_add'],
  ['Edit', 'can_edit'],
  ['Delete', 'can_delete'],
  ['Export', 'can_export'],
  ['Import', 'can_import'],
  ['Approve', 'can_approve'],
];

function roleVisuals(roleName) {
  const known = roleCards.find((item) => item.name === roleName);
  return { icon: known?.icon ?? ShieldCheck, tone: known?.tone ?? 'blue' };
}

function RolesPermissionsPage({ onNotify, onOpenSection, loggedInUser }) {
  const isSuperAdmin = Boolean(loggedInUser?.is_super_admin);
  const [roles, setRoles] = useState([]);
  const [selectedRoleId, setSelectedRoleId] = useState(null);
  const [activeTab, setActiveTab] = useState('Permissions');
  const [addRoleOpen, setAddRoleOpen] = useState(false);
  const [permissions, setPermissions] = useState([]);
  const [roleUsers, setRoleUsers] = useState([]);
  const [loadingPermissions, setLoadingPermissions] = useState(false);
  const [saving, setSaving] = useState(false);

  const selectedRole = roles.find((role) => role.id === selectedRoleId) ?? null;

  useEffect(() => {
    if (!isSuperAdmin) return;
    roleApi.list().then((data) => {
      const list = data?.results ?? data ?? [];
      setRoles(list);
      if (list.length) setSelectedRoleId(list[0].id);
    }).catch((error) => onNotify?.(error.message || 'Failed to load roles'));
  }, [isSuperAdmin]);

  useEffect(() => {
    if (!isSuperAdmin || !selectedRoleId) return;
    setLoadingPermissions(true);
    roleApi.getPermissions(selectedRoleId).then((data) => {
      setPermissions(data ?? []);
    }).catch((error) => onNotify?.(error.message || 'Failed to load permissions')).finally(() => setLoadingPermissions(false));
    userApi.list({ role: selectedRoleId }).then((data) => {
      setRoleUsers((data?.results ?? data ?? []).map(mapApiUserToRow));
    }).catch(() => setRoleUsers([]));
  }, [isSuperAdmin, selectedRoleId]);

  if (!isSuperAdmin) {
    return (
      <div className="space-y-4">
        <PageHeading title="Roles & Permissions" crumbs={[{ label: 'Roles & Permissions' }]} />
        <section className={`${panelClass} flex flex-col items-center justify-center gap-3 p-10 text-center`}>
          <ShieldCheck className="size-10 text-[#d98200]" />
          <h2 className="font-display text-[16px] font-extrabold text-[#1e3261]">Super Admin access required</h2>
          <p className="max-w-[420px] text-[13px] font-bold text-[#53647f]">Roles and module permissions are managed exclusively by the Super Admin.</p>
        </section>
      </div>
    );
  }

  const togglePermission = (module, field) => {
    setPermissions((current) => current.map((row) => (row.module === module ? { ...row, [field]: !row[field] } : row)));
  };

  const toggleFullAccess = (module) => {
    setPermissions((current) => current.map((row) => (row.module === module ? { ...row, full_access: !row.full_access } : row)));
  };

  const savePermissions = () => {
    setSaving(true);
    roleApi.setPermissions(selectedRoleId, permissions)
      .then((data) => {
        setPermissions(data ?? permissions);
        onNotify(`${selectedRole?.name ?? 'Role'} permissions saved`);
      })
      .catch((error) => onNotify(error.message || 'Failed to save permissions'))
      .finally(() => setSaving(false));
  };

  const resetPermissions = () => {
    setPermissions((current) => current.map((row) => ({
      ...row, can_view: false, can_add: false, can_edit: false, can_delete: false,
      can_export: false, can_import: false, can_approve: false, full_access: false,
    })));
    onNotify('Permissions reset — click Save Permissions to apply');
  };

  return (
    <div className="space-y-4">
      <PageHeading
        title="Roles & Permissions"
        crumbs={[
          { label: 'Dashboard', onClick: () => onOpenSection?.('Dashboard') },
          { label: 'Settings', onClick: () => onNotify('Settings breadcrumb selected') },
          { label: 'Roles & Permissions' },
        ]}
      />

      <section className="grid gap-4 xl:grid-cols-[300px_minmax(0,1fr)]">
        <article className={`${panelClass} flex min-h-[620px] flex-col overflow-hidden p-4`}>
          <div className="mb-4 flex items-center justify-between gap-3">
            <h2 className="font-display text-[16px] font-extrabold text-[#1e3261]">Roles List</h2>
            <button
              type="button"
              onClick={() => setAddRoleOpen(true)}
              className="inline-flex h-9 items-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-3 text-[12px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"
            >
              <Plus className="size-4" />
              Add Role
            </button>
          </div>
          <div className="space-y-2">
            {roles.map((roleItem) => {
              const { icon: RoleIcon, tone } = roleVisuals(roleItem.name);
              const active = selectedRoleId === roleItem.id;
              return (
                <button
                  key={roleItem.id}
                  type="button"
                  onClick={() => {
                    setSelectedRoleId(roleItem.id);
                    onNotify(`${roleItem.name} role selected`);
                  }}
                  className={cx(
                    'flex w-full items-center gap-3 rounded-[10px] border px-3 py-3 text-left transition',
                    active ? 'border-[#cbeed7] bg-[#effbf3]' : 'border-transparent bg-white hover:border-[#e7eef7] hover:bg-[#f8fbff]',
                  )}
                >
                  <span className={cx('grid size-10 place-items-center rounded-full', getRoleToneClass(tone))}>
                    <RoleIcon className="size-5" />
                  </span>
                  <span className="min-w-0 flex-1">
                    <span className="block text-[13px] font-extrabold text-[#1e3261]">{roleItem.name}</span>
                    <span className="mt-1 block text-[11px] font-bold text-[#6f7f98]">{roleItem.role_type === 'system' ? 'System Role' : 'Custom Role'}</span>
                  </span>
                  <span className="rounded-[7px] border border-[#d9e4f2] bg-white px-2 py-1 text-[11px] font-extrabold text-[#53647f]">{roleItem.user_count ?? 0}</span>
                </button>
              );
            })}
          </div>
          <div className="mt-auto border-t border-[#edf2f8] pt-4 text-[13px] font-bold text-[#53647f]">Total Roles: {roles.length}</div>
        </article>

        {selectedRole ? (
        <article className={`${panelClass} overflow-hidden p-4 sm:p-5`}>
          <h2 className="font-display text-[16px] font-extrabold text-[#1e3261]">Role Details</h2>
          <div className="mt-4 grid gap-4 lg:grid-cols-[0.75fr_1.25fr]">
            <LeadInput label="Role Name" required placeholder={selectedRole.name} />
            <LeadInput label="Role Description" placeholder={selectedRole.description || `Can manage ${selectedRole.name.toLowerCase()} access and assigned work.`} />
          </div>

          <div className="mt-6 flex flex-col gap-3 border-b border-[#edf2f8] sm:flex-row sm:items-center sm:justify-between">
            <div className="flex gap-6 text-[13px] font-extrabold">
              {['Permissions', `Users with this Role (${roleUsers.length})`].map((tab) => (
                <button
                  key={tab}
                  type="button"
                  onClick={() => setActiveTab(tab.startsWith('Users') ? 'Users' : 'Permissions')}
                  className={cx('pb-3', (tab.startsWith(activeTab) || (activeTab === 'Users' && tab.startsWith('Users'))) ? 'border-b-2 border-[#0d9f4a] text-[#0d9f4a]' : 'text-[#53647f]')}
                >
                  {tab}
                </button>
              ))}
            </div>
            {activeTab === 'Permissions' ? (
              <div className="mb-3 flex flex-col gap-3 sm:flex-row">
                <button type="button" onClick={resetPermissions} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]">
                  <RefreshCw className="size-4" />
                  Reset to Default
                </button>
              </div>
            ) : null}
          </div>

          {activeTab === 'Permissions' ? (
            <div className="mt-4">
              <h3 className="mb-3 text-[14px] font-extrabold text-[#1e3261]">Module Permissions</h3>
              {loadingPermissions ? (
                <PageLoadingState message="Loading permissions..." compact />
              ) : (
              <div className="overflow-x-auto rounded-[12px] border border-[#e7eef7] bg-white">
                <table className="crm-table min-w-[920px] w-full">
                  <thead><tr>{['Module', ...PERMISSION_ACTION_FIELDS.map(([label]) => label), 'Full Access'].map((header) => <th key={header}>{header}</th>)}</tr></thead>
                  <tbody>
                    {permissions.map((row) => {
                      const isLocked = row.module === 'User Management';
                      return (
                        <tr key={row.module}>
                          <td className="font-extrabold text-[#1e3261]">
                            {row.module}
                            {isLocked ? <span className="ml-2 text-[10px] font-bold text-[#9aa8bc]">(Super Admin only)</span> : null}
                          </td>
                          {PERMISSION_ACTION_FIELDS.map(([label, field]) => (
                            <td key={`${row.module}-${field}`}>
                              {isLocked ? (
                                <span className="text-[#9aa8bc]">-</span>
                              ) : (
                                <input
                                  type="checkbox"
                                  checked={Boolean(row.full_access || row[field])}
                                  disabled={row.full_access}
                                  onChange={() => togglePermission(row.module, field)}
                                  className="size-4 rounded border-[#b9c4d6] accent-[#0d9f4a]"
                                  aria-label={`${row.module} ${label}`}
                                />
                              )}
                            </td>
                          ))}
                          <td>
                            {isLocked ? (
                              <span className="text-[#9aa8bc]">-</span>
                            ) : (
                              <input
                                type="checkbox"
                                checked={Boolean(row.full_access)}
                                onChange={() => toggleFullAccess(row.module)}
                                className="size-4 rounded border-[#b9c4d6] accent-[#0d9f4a]"
                                aria-label={`${row.module} Full Access`}
                              />
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
              )}
              <button type="button" disabled={saving || loadingPermissions} onClick={savePermissions} className="mt-5 h-11 rounded-[8px] bg-[#0d9f4a] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(13,159,74,0.22)] transition hover:bg-[#078c3e] disabled:opacity-60">
                {saving ? 'Saving...' : 'Save Permissions'}
              </button>
            </div>
          ) : (
            <div className="mt-4 grid gap-3 md:grid-cols-2 xl:grid-cols-3">
              {roleUsers.length ? roleUsers.map((user) => (
                <article key={user.id} className="rounded-[12px] border border-[#e7eef7] bg-white p-4">
                  <AssigneeCell assignee={user.assignee} />
                  <p className="mt-2 text-[12px] font-bold text-[#6f7f98]">{user.email}</p>
                  <p className="mt-3"><EmployeeStatusBadge status={user.status} /></p>
                </article>
              )) : <p className="text-[13px] font-bold text-[#7585a2]">No users assigned to this role yet.</p>}
            </div>
          )}
        </article>
        ) : <article className={`${panelClass} p-6 text-[13px] font-bold text-[#7585a2]`}>Select a role to view its permissions.</article>}
      </section>

      <DashboardFooter />

      {addRoleOpen ? (
        <AddRoleModal
          onClose={() => setAddRoleOpen(false)}
          onSave={(roleName) => {
            roleApi.create({ name: roleName, role_type: 'custom' }).then((newRole) => {
              setRoles((current) => [...current, newRole]);
              setSelectedRoleId(newRole.id);
              setAddRoleOpen(false);
              onNotify(`${roleName} role added`);
            }).catch((error) => onNotify(error.message || 'Failed to add role'));
          }}
        />
      ) : null}
    </div>
  );
}

function ActivityLogsPage({ onNotify, onOpenSection }) {
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const [dateFrom, setDateFrom] = useState('2026-07-01');
  const [dateTo, setDateTo] = useState('2026-07-03');
  const [user, setUser] = useState('All Users');
  const [moduleName, setModuleName] = useState('All Modules');
  const [action, setAction] = useState('All Actions');
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  // BUG-009: this page used to render a hardcoded mock array; it now shares the
  // same real API as SettingsUserActivityLogPage instead of a second fake source.
  useEffect(() => {
    setLoading(true);
    settingsApi.activityLogs.list()
      .then((res) => {
        const list = Array.isArray(res) ? res : (res?.results ?? []);
        setLogs(list.map(mapActivityLogFromApi));
      })
      .catch(() => onNotify?.('Could not load activity logs.', 'error'))
      .finally(() => setLoading(false));
  }, []);  

  const uniqueUsers = [...new Set(logs.map((log) => log.user.name))];

  const filteredLogs = logs.filter((log) => {
    const userMatch = user === 'All Users' || log.user.name === user;
    const moduleMatch = moduleName === 'All Modules' || log.module === moduleName;
    const actionMatch = action === 'All Actions' || log.action === action;
    return userMatch && moduleMatch && actionMatch;
  });

  const resetLogs = () => {
    setUser('All Users');
    setModuleName('All Modules');
    setAction('All Actions');
    setDateFrom('2026-07-01');
    setDateTo('2026-07-03');
    onNotify('Activity log filters reset');
  };

  return (
    <div className="space-y-4">
      <PageHeading
        title="Activity Logs"
        crumbs={[
          { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
          { label: 'Settings', onClick: () => onNotify('Settings breadcrumb selected') },
          { label: 'Activity Logs' },
        ]}
        actions={(
          <button type="button" onClick={() => onNotify('Activity logs exported')} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]">
            <Download className="size-4 text-[#0b65e5]" />
            Export Logs
          </button>
        )}
      />

      <section className={`${panelClass} relative z-40 p-4 sm:p-5`}>
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-[1.2fr_0.95fr_1fr_1fr_auto_auto] xl:items-end">
          <ReportDateRangePicker open={dateRangeOpen} onToggle={() => setDateRangeOpen((value) => !value)} onClose={() => setDateRangeOpen(false)} dateFrom={dateFrom} dateTo={dateTo} setDateFrom={setDateFrom} setDateTo={setDateTo} formattedRange={`${formatReportDate(dateFrom)} - ${formatReportDate(dateTo)}`} />
          <ReportSelect label="User" value={user} onChange={setUser} options={['All Users', ...uniqueUsers]} />
          <ReportSelect label="Module" value={moduleName} onChange={setModuleName} options={['All Modules', 'Leads', 'Follow-ups', 'IVRS Management', 'Approvals', 'Users', 'Roles & Permissions', 'Settings']} />
          <ReportSelect label="Action" value={action} onChange={setAction} options={['All Actions', 'Created', 'Updated', 'Requested', 'Approved', 'Edited', 'Deleted']} />
          <button type="button" onClick={() => onNotify(`Activity filters applied: ${filteredLogs.length} entries`)} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"><RefreshCw className="size-4 text-[#0b65e5]" />Filters</button>
          <button type="button" onClick={resetLogs} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"><RefreshCw className="size-4 text-[#7585a2]" />Reset</button>
        </div>
      </section>

      <section className={`${panelClass} overflow-hidden p-3 sm:p-4`}>
        {loading && (
          <div className="flex items-center justify-center py-16 text-[14px] text-[#7a8fa6]">Loading activity logs...</div>
        )}
        {!loading && filteredLogs.length === 0 && (
          <div className="flex items-center justify-center py-16 text-[14px] text-[#7a8fa6]">No activity logs found.</div>
        )}
        <div className={cx('space-y-3 lg:hidden', loading && 'hidden')}>
          {filteredLogs.map((log) => (
            <article key={log.id} className="rounded-[14px] border border-[#e7eef7] bg-white p-4 shadow-[0_10px_22px_rgba(17,39,84,0.05)]">
              <div className="flex items-start justify-between gap-3">
                <AssigneeCell assignee={log.user.assignee} compact />
                <ActivityActionBadge action={log.action} />
              </div>
              <p className="mt-3 text-[12px] font-bold text-[#53647f]">{log.time}</p>
              <div className="mt-3"><ModuleBadge module={log.module} /></div>
              <p className="mt-3 text-[13px] font-semibold leading-6 text-[#314a79]">{log.description}</p>
              <p className="mt-3 text-[12px] font-bold text-[#6f7f98]">IP: {log.ip}</p>
            </article>
          ))}
        </div>

        <div className={cx('hidden overflow-x-auto rounded-[12px] border border-[#e7eef7] bg-white', !loading && 'lg:block')}>
          <table className="crm-table min-w-[1180px] w-full">
            <thead><tr>{['#', 'Date & Time', 'User', 'Module', 'Action', 'Details', 'IP Address'].map((header) => <th key={header}>{header}</th>)}</tr></thead>
            <tbody>
              {filteredLogs.map((log, index) => (
                <tr key={log.id} onClick={() => onNotify(`Activity log #${log.id} opened`)} className="cursor-pointer">
                  <td>{index + 1}</td>
                  <td className="font-extrabold text-[#1e3261]">{log.time}</td>
                  <td><AssigneeCell assignee={log.user.assignee} compact /></td>
                  <td><ModuleBadge module={log.module} /></td>
                  <td><ActivityActionBadge action={log.action} /></td>
                  <td className="max-w-[360px] whitespace-normal leading-5">{log.description}</td>
                  <td>{log.ip}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="flex flex-col gap-4 px-3 py-5 text-[13px] font-bold text-[#53647f] sm:flex-row sm:items-center sm:justify-between">
          <p>Showing 1 to {filteredLogs.length} of {logs.length} entries</p>
          <div className="flex flex-wrap items-center gap-2">
            <PaginationButton onClick={() => onNotify('Previous activity page selected')}><ChevronLeft className="size-4" /></PaginationButton>
            <PaginationButton active onClick={() => onNotify('Activity page 1 selected')}>1</PaginationButton>
            <PaginationButton onClick={() => onNotify('Activity page 2 selected')}>2</PaginationButton>
            <PaginationButton onClick={() => onNotify('Activity page 3 selected')}>3</PaginationButton>
            <span className="px-2 text-[#53647f]">...</span>
            <PaginationButton onClick={() => onNotify('Activity page 13 selected')}>13</PaginationButton>
            <PaginationButton onClick={() => onNotify('Next activity page selected')}><ChevronRight className="size-4" /></PaginationButton>
          </div>
        </div>
      </section>

      <DashboardFooter />
    </div>
  );
}

