function ReportsPage({ onOpenSection, onNotify }) {
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const [dateFrom, setDateFrom] = useState('2024-05-01');
  const [dateTo, setDateTo] = useState('2024-05-20');
  const [projectType, setProjectType] = useState('All');
  const [leadStatus, setLeadStatus] = useState('All');
  const [assignedTo, setAssignedTo] = useState('All');
  const [assigneeOptions, setAssigneeOptions] = useState(['All']);
  const [trendView, setTrendView] = useState('Daily');
  const [selectedStatus, setSelectedStatus] = useState('New');
  const [filtersApplied, setFiltersApplied] = useState(false);
  const [analyticsData, setAnalyticsData] = useState(null);
  const [analyticsLoading, setAnalyticsLoading] = useState(false);
  const [dashboardData, setDashboardData] = useState(null);
  const [incentiveReportOpen, setIncentiveReportOpen] = useState(false);

  useEffect(() => {
    userApi.list({ page_size: 500 })
      .then((data) => {
        const names = [...new Set(normalizeApiRows(data).map((user) => user.name).filter(Boolean))];
        setAssigneeOptions(['All', ...names]);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    setAnalyticsLoading(true);
    const params = {};
    if (dateFrom) params.date_from = dateFrom;
    if (dateTo) params.date_to = dateTo;
    if (projectType !== 'All') params.project_type = projectType;
    if (leadStatus !== 'All') params.status = leadStatus;
    if (assignedTo !== 'All') params.assigned_to = assignedTo;
    Promise.all([
      analyticsApi.leads(params),
      reportsApi.dashboard(params),
    ]).then(([leads, dashboard]) => {
      if (leads) setAnalyticsData(leads);
      if (dashboard) setDashboardData(dashboard);
    }).catch(() => onNotify('Report data could not be loaded.', 'error')).finally(() => setAnalyticsLoading(false));
  }, [dateFrom, dateTo, projectType, leadStatus, assignedTo, filtersApplied]);

  const formattedRange = `${formatReportDate(dateFrom)} - ${formatReportDate(dateTo)}`;

  const applyFilters = () => {
    setFiltersApplied(true);
    setDateRangeOpen(false);
    onNotify(`Reports filtered: ${projectType}, ${leadStatus}, ${assignedTo}`);
  };

  const resetFilters = () => {
    setDateFrom('2024-05-01');
    setDateTo('2024-05-20');
    setProjectType('All');
    setLeadStatus('All');
    setAssignedTo('All');
    setTrendView('Daily');
    setSelectedStatus('New');
    setFiltersApplied(false);
    setDateRangeOpen(false);
    onNotify('Reports filters reset');
  };

  return (
    <div className="space-y-4">
      <PageHeading
        title="Reports & Analytics"
        crumbs={[
          { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
          { label: 'Reports & Analytics' },
        ]}
        actions={(
          <>
            <button
              type="button"
              onClick={() => {
                const rows = (analyticsData?.project_type_stats ?? []).map((p) => [
                  p.type || 'Unknown',
                  p.total,
                  p.won,
                  `${p.conversion}%`,
                ]);
                exportNotifyCsv(onNotify, 'reports-analytics', ['Project Type', 'Total', 'Won', 'Conversion'], rows);
              }}
              data-action="reports-export"
              className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[13px] font-extrabold text-[#284276] shadow-[0_8px_18px_rgba(17,39,84,0.04)] transition hover:border-[#c8d8ed] hover:bg-[#f8fbff]"
            >
              <Download className="size-4 text-[#0b65e5]" />
              Export Report
            </button>
            <button
              type="button"
              onClick={() => setIncentiveReportOpen(true)}
              data-action="reports-generate-incentive"
              className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#ef4444] px-4 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(239,68,68,0.22)] transition hover:-translate-y-0.5 hover:bg-[#dc2626]"
            >
              <IndianRupee className="size-4" />
              Generate Incentive Report
            </button>
          </>
        )}
      />

      {incentiveReportOpen ? (
        <IncentiveReportModal onClose={() => setIncentiveReportOpen(false)} onNotify={onNotify} />
      ) : null}

      <section className={`${panelClass} relative z-40 p-4 sm:p-5`}>
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-[1.25fr_0.9fr_0.9fr_0.9fr_auto] xl:items-end">
          <ReportDateRangePicker
            open={dateRangeOpen}
            onToggle={() => setDateRangeOpen((value) => !value)}
            onClose={() => setDateRangeOpen(false)}
            dateFrom={dateFrom}
            dateTo={dateTo}
            setDateFrom={setDateFrom}
            setDateTo={setDateTo}
            formattedRange={formattedRange}
          />
          <ReportSelect label="Project Type" value={projectType} onChange={setProjectType} options={['All', 'On-Grid', 'Off-Grid', 'Hybrid']} />
          <ReportSelect label="Lead Status" value={leadStatus} onChange={setLeadStatus} options={LEAD_STATUS_FILTER_OPTIONS} />
          <ReportSelect label="Assigned To" value={assignedTo} onChange={setAssignedTo} options={assigneeOptions} />
          <div className="grid gap-3 sm:grid-cols-2 xl:min-w-[150px] xl:grid-cols-1">
            <button
              type="button"
              onClick={applyFilters}
              data-action="reports-apply-filters"
              className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#0d9f4a] px-4 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(13,159,74,0.22)] transition hover:-translate-y-0.5 hover:bg-[#078c3e]"
            >
              <RefreshCw className="size-4" />
              Apply Filters
            </button>
            <button
              type="button"
              onClick={resetFilters}
              data-action="reports-reset"
              className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[13px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"
            >
              <RefreshCw className="size-4 text-[#7585a2]" />
              Reset
            </button>
          </div>
        </div>
        {filtersApplied ? (
          <div className="mt-4 rounded-[10px] border border-[#d9f2e4] bg-[#f4fff8] px-4 py-3 text-[12px] font-bold text-[#276747]">
            Active report view: {formattedRange} | {projectType} | {leadStatus} | {assignedTo}
          </div>
        ) : null}
      </section>

      <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-5">
        {(dashboardData?.kpis ?? reportKpis).map((kpi) => (
          <ReportKpiCard key={kpi.title} kpi={{ ...kpi, icon: reportKpiIconMap[kpi.tone] || Users, caption: kpi.caption || '' }} onClick={() => onNotify(`${kpi.title} report opened`)} />
        ))}
      </section>

      {dashboardData?.operations ? (
        <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">
          {[
            { label: 'Active Projects', value: dashboardData.projects?.active ?? 0 },
            { label: 'Revenue (Period)', value: fmtAccRs(dashboardData.revenue) },
            { label: 'Open O&M Tickets', value: dashboardData.operations.open_tickets ?? 0 },
            { label: 'Active AMC', value: dashboardData.operations.active_amc ?? 0 },
          ].map((item) => (
            <article key={item.label} className={`${panelClass} p-4`}>
              <p className="text-[12px] font-bold text-[#7a8fa6]">{item.label}</p>
              <p className="mt-2 text-[22px] font-extrabold text-[#1e3261]">{item.value}</p>
            </article>
          ))}
        </section>
      ) : null}

      <section className="grid gap-4 xl:grid-cols-[minmax(0,1.15fr)_minmax(360px,0.85fr)]">
        <article className={`${panelClass} overflow-hidden p-4 sm:p-5`}>
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <h2 className="font-display text-[18px] font-extrabold text-[#111827]">Leads Trend</h2>
            <ReportSelect
              label="Trend View"
              value={trendView}
              onChange={(value) => {
                setTrendView(value);
                onNotify(`${value} trend selected`);
              }}
              options={['Daily', 'Weekly', 'Monthly']}
              hideLabel
              className="sm:w-[120px]"
            />
          </div>
          <ReportLineChart data={analyticsData?.monthly_trend ?? []} loading={analyticsLoading} />
        </article>

        <article className={`${panelClass} overflow-hidden p-4 sm:p-5`}>
          <h2 className="font-display text-[18px] font-extrabold text-[#111827]">Leads by Status</h2>
          <ReportDonut data={analyticsData?.status_distribution ?? []} loading={analyticsLoading} />
        </article>
      </section>

      <section className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(0,1fr)_minmax(320px,0.78fr)]">
        <ReportTableCard
          title="Leads by Project Type"
          headers={['Project Type', 'Total Leads', 'Won Leads', 'Conversion Rate']}
          rows={analyticsData?.project_type_stats?.map((p) => [p.type || 'Unknown', p.total, p.won, `${p.conversion}%`]) ?? []}
          onRowClick={(row) => onNotify(`${row[0]} project report opened`)}
        />
        <ReportEmployeeCard data={analyticsData?.employee_stats ?? []} loading={analyticsLoading} onNotify={onNotify} />
        <ReportIvrsSummary analyticsData={analyticsData} onNotify={onNotify} />
      </section>

      <DashboardFooter />
    </div>
  );
}

const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

function IncentiveReportModal({ onClose, onNotify }) {
  const today = new Date();
  const [month, setMonth] = useState(today.getMonth() + 1);
  const [year, setYear] = useState(today.getFullYear());
  const [manager, setManager] = useState('All');
  const [ratePerWon, setRatePerWon] = useState('');
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const lastDay = new Date(year, month, 0).getDate();
    const dateFrom = `${year}-${String(month).padStart(2, '0')}-01`;
    const dateTo = `${year}-${String(month).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;
    analyticsApi.leads({ date_from: dateFrom, date_to: dateTo })
      .then((data) => { if (!cancelled) setRows(data?.employee_stats ?? []); })
      .catch(() => { if (!cancelled) setRows([]); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [month, year]);

  const managerOptions = useMemo(() => ['All', ...rows.map((r) => r.name)], [rows]);
  const visibleRows = manager === 'All' ? rows : rows.filter((r) => r.name === manager);
  const rate = Number(ratePerWon) || 0;
  const totalWon = visibleRows.reduce((sum, r) => sum + (r.won || 0), 0);
  const totalIncentive = totalWon * rate;
  const periodLabel = `${monthNames[month - 1]} ${year}`;

  const handleGenerate = () => {
    if (!visibleRows.length) {
      onNotify(`No records found for ${periodLabel}`);
      return;
    }
    const win = window.open('', '_blank');
    if (!win) { onNotify('Allow pop-ups to generate this report'); return; }
    win.document.write(buildIncentiveReportHtml(visibleRows, { periodLabel, rate, totalWon, totalIncentive }));
    win.document.close();
    win.focus();
    win.onload = () => { win.print(); };
    setTimeout(() => { try { win.print(); } catch { /* ignore */ } }, 600);
  };

  return (
    <div className="modal-overlay fixed inset-0 z-100 flex items-center justify-center bg-[#111827]/55 p-4" onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}>
      <div className="modal-pop-in w-full max-w-[640px] rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between gap-3 border-b border-[#edf2f8] px-6 py-4">
          <h2 className="flex items-center gap-2 font-display text-[16px] font-extrabold text-[#111827]">
            <IndianRupee className="size-5 text-[#ef4444]" />
            Incentive Report
          </h2>
          <button type="button" onClick={onClose} aria-label="Close" className="grid size-8 place-items-center rounded-[7px] text-[#7386a3] hover:bg-[#f1f5fb]">
            <X className="size-4" />
          </button>
        </div>

        <div className="max-h-[70vh] overflow-y-auto px-6 py-5">
          <div className="grid gap-3 sm:grid-cols-3">
            <ReportSelect label="Month" hideLabel value={String(month)} onChange={(v) => setMonth(Number(v))} options={monthNames.map((_, i) => String(i + 1))} optionLabels={Object.fromEntries(monthNames.map((n, i) => [String(i + 1), n]))} />
            <ReportSelect label="Year" hideLabel value={String(year)} onChange={(v) => setYear(Number(v))} options={[year - 1, year, year + 1].map(String)} />
            <ReportSelect label="Manager" hideLabel value={manager} onChange={setManager} options={managerOptions} optionLabels={{ All: 'All Managers' }} />
          </div>

          <label className="mt-3 block">
            <span className="mb-2 block text-[12px] font-extrabold text-[#34466c]">Incentive per Won Lead (₹)</span>
            <input
              type="number"
              min="0"
              value={ratePerWon}
              onChange={(event) => setRatePerWon(event.target.value)}
              placeholder="Enter your incentive rate, e.g. 500"
              className="h-11 w-full rounded-[8px] border border-black/20 bg-white px-4 text-[13px] font-bold text-[#30466d] outline-none transition placeholder:text-[#8493ab] focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
            />
          </label>

          <div className="mt-4 flex items-center justify-between text-[12px] font-extrabold text-[#7386a3]">
            <span>{periodLabel}</span>
            <span>{visibleRows.length} record{visibleRows.length === 1 ? '' : 's'}</span>
          </div>

          <div className="mt-2 overflow-hidden rounded-[12px] border border-[#e7eef7] bg-white">
            {loading ? (
              <PageLoadingState message="Loading..." className="h-[160px] py-0" compact />
            ) : visibleRows.length > 0 ? (
              <table className="crm-table w-full">
                <thead>
                  <tr>{['Executive', 'Total Leads', 'Won', 'Conversion', 'Incentive'].map((h) => <th key={h}>{h}</th>)}</tr>
                </thead>
                <tbody>
                  {visibleRows.map((row) => (
                    <tr key={row.name}>
                      <td className="font-bold text-[#1e3261]">{row.name}</td>
                      <td>{row.total}</td>
                      <td>{row.won}</td>
                      <td>{row.conversion}%</td>
                      <td className="font-extrabold text-[#0d9f4a]">₹{((row.won || 0) * rate).toLocaleString('en-IN')}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div className="flex h-[120px] items-center justify-center text-[13px] font-bold text-[#8a98af]">
                No records found for {periodLabel}
              </div>
            )}
          </div>

          {visibleRows.length > 0 ? (
            <div className="mt-3 flex items-center justify-between rounded-[10px] border border-[#d9f2e4] bg-[#f4fff8] px-4 py-3 text-[13px] font-extrabold text-[#276747]">
              <span>Total Won: {totalWon}</span>
              <span>Total Incentive: ₹{totalIncentive.toLocaleString('en-IN')}</span>
            </div>
          ) : null}
        </div>

        <div className="flex justify-end gap-3 border-t border-[#edf2f8] px-6 py-4">
          <button type="button" onClick={handleGenerate} className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#ef4444] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(239,68,68,0.22)] transition hover:bg-[#dc2626]">
            <FileText className="size-4" />
            Generate Report
          </button>
          <button type="button" onClick={onClose} className="h-11 rounded-[8px] border border-black/20 bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff]">Cancel</button>
        </div>
      </div>
    </div>
  );
}

function buildIncentiveReportHtml(rows, { periodLabel, rate, totalWon, totalIncentive }) {
  const esc = (v) => String(v ?? '').replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
  const bodyRows = rows.map((row) => `
    <tr>
      <td>${esc(row.name)}</td>
      <td class="n">${esc(row.total)}</td>
      <td class="n">${esc(row.won)}</td>
      <td class="n">${esc(row.conversion)}%</td>
      <td class="n">₹${((row.won || 0) * rate).toLocaleString('en-IN')}</td>
    </tr>`).join('');

  return `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<title>Incentive Report — ${esc(periodLabel)}</title>
<style>
  body { font-family: Arial, sans-serif; color: #1e293b; padding: 32px; }
  h1 { font-size: 20px; margin: 0 0 2px; color: #ef4444; }
  .sub { font-size: 12px; color: #64748b; margin-bottom: 24px; }
  table { border-collapse: collapse; width: 100%; }
  th, td { border: 1px solid #e2e8f0; padding: 8px 12px; font-size: 12px; text-align: left; }
  th { background: #fef2f2; color: #ef4444; }
  .n { text-align: right; }
  tfoot td { font-weight: bold; background: #f4fff8; color: #0d9f4a; }
  .footer { margin-top: 24px; font-size: 11px; color: #94a3b8; }
</style>
</head>
<body>
  <h1>Malwa Solar Energy</h1>
  <div class="sub">Incentive Report — ${esc(periodLabel)}${rate ? ` • ₹${esc(rate)} per won lead` : ''}</div>
  <table>
    <thead><tr><th>Executive</th><th class="n">Total Leads</th><th class="n">Won</th><th class="n">Conversion</th><th class="n">Incentive</th></tr></thead>
    <tbody>${bodyRows}</tbody>
    <tfoot><tr><td colspan="2"></td><td class="n">${esc(totalWon)}</td><td></td><td class="n">₹${totalIncentive.toLocaleString('en-IN')}</td></tr></tfoot>
  </table>
  <div class="footer">Generated on ${esc(new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'long', year: 'numeric' }))}</div>
</body>
</html>`;
}

function ReportDateRangePicker({ open, onToggle, onClose, dateFrom, dateTo, setDateFrom, setDateTo, formattedRange, hideLabel = false }) {
  return (
    <div className="relative">
      {!hideLabel ? <span className="mb-2 block text-[12px] font-extrabold text-[#34466c]">Date Range</span> : null}
      <button
        type="button"
        onClick={onToggle}
        className="flex h-11 w-full items-center justify-between gap-3 rounded-[8px] border border-black/20 bg-white px-4 text-left text-[13px] font-bold text-[#30466d] transition hover:bg-[#fbfdff] focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
      >
        <span className="inline-flex min-w-0 items-center gap-3">
          <CalendarDays className="size-4 shrink-0 text-[#7386a3]" />
          <span className="truncate">{formattedRange}</span>
        </span>
        <ChevronRight className={cx('size-4 shrink-0 text-[#7386a3] transition', open && 'rotate-90')} />
      </button>
      {open ? (
        <div className="absolute left-0 top-[calc(100%+8px)] z-90 w-full min-w-[280px] rounded-[14px] border border-[#dbe5f2] bg-white p-4 shadow-[0_18px_44px_rgba(24,48,87,0.18)]">
          <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-1 2xl:grid-cols-2">
            <label className="block">
              <span className="mb-2 block text-[11px] font-extrabold uppercase text-[#8493ab]">From</span>
              <input
                type="date"
                value={dateFrom}
                onChange={(event) => setDateFrom(event.target.value)}
                className="h-10 w-full rounded-[8px] border border-black/20 bg-white px-3 text-[13px] font-bold text-[#30466d] transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
              />
            </label>
            <label className="block">
              <span className="mb-2 block text-[11px] font-extrabold uppercase text-[#8493ab]">To</span>
              <input
                type="date"
                value={dateTo}
                onChange={(event) => setDateTo(event.target.value)}
                className="h-10 w-full rounded-[8px] border border-black/20 bg-white px-3 text-[13px] font-bold text-[#30466d] transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
              />
            </label>
          </div>
          <div className="mt-4 flex justify-end">
            <button
              type="button"
              onClick={onClose}
              className="h-9 rounded-[8px] bg-[#0d9f4a] px-4 text-[12px] font-extrabold text-white transition hover:bg-[#078c3e]"
            >
              Done
            </button>
          </div>
        </div>
      ) : null}
    </div>
  );
}

function ReportSelect({ label, value, onChange, options, optionLabels, hideLabel = false, className = '' }) {
  return (
    <label className={cx('block min-w-0', className)}>
      {!hideLabel ? <span className="mb-2 block text-[12px] font-extrabold text-[#34466c]">{label}</span> : null}
      <select
        value={value}
        onChange={(event) => onChange(event.target.value)}
        aria-label={label}
        className="h-11 w-full rounded-[8px] border border-black/20 bg-white px-4 text-[13px] font-bold text-[#30466d] outline-none transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
      >
        {options.map((option) => (
          <option key={option} value={option}>{optionLabels?.[option] ?? option}</option>
        ))}
      </select>
    </label>
  );
}

function ReportKpiCard({ kpi, onClick }) {
  const Icon = kpi.icon;
  const tone = reportKpiToneClasses[kpi.tone] || reportKpiToneClasses.blue;

  return (
    <button
      type="button"
      onClick={onClick}
      className={cx(
        `${panelClass} min-h-[112px] p-4 text-left transition hover:-translate-y-0.5 hover:shadow-[0_16px_34px_rgba(24,48,87,0.1)]`,
        tone,
      )}
    >
      <div className="flex items-center gap-4">
        <span className="grid size-12 shrink-0 place-items-center rounded-full bg-current/10">
          <Icon className="size-6" />
        </span>
        <div className="min-w-0">
          <p className="truncate text-[13px] font-extrabold text-[#263d72]">{kpi.title}</p>
          <p className="mt-1 font-display text-[25px] font-extrabold leading-none text-[#111827]">
            {kpi.value}
            <span className="ml-2 inline-flex items-center gap-1 align-middle text-[12px] font-extrabold text-[#0d9f4a]">
              <ArrowUpRight className="size-3.5" />
              {kpi.growth}
            </span>
          </p>
          <p className="mt-3 text-[11px] font-bold text-[#53647f]">{kpi.caption}</p>
        </div>
      </div>
    </button>
  );
}

function ReportLineChart({ data, loading }) {
  if (loading) {
    return <PageLoadingState message="Loading chart..." className="h-[280px] py-0" compact />;
  }
  if (!data || data.length === 0) {
    return <div className="flex h-[280px] items-center justify-center text-[13px] font-bold text-[#8a98af]">No data available</div>;
  }
  return (
    <div className="mt-4 h-[280px]">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data} margin={{ top: 10, right: 10, left: -10, bottom: 0 }}>
          <defs>
            <linearGradient id="colorNew" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#1f7ff0" stopOpacity={0.15} />
              <stop offset="95%" stopColor="#1f7ff0" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="colorWon" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#36a269" stopOpacity={0.15} />
              <stop offset="95%" stopColor="#36a269" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="colorFollowUp" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#6b55e9" stopOpacity={0.15} />
              <stop offset="95%" stopColor="#6b55e9" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#edf2f8" />
          <XAxis dataKey="month" tick={{ fontSize: 11, fontWeight: 700, fill: '#53647f' }} axisLine={false} tickLine={false} />
          <YAxis tick={{ fontSize: 11, fontWeight: 700, fill: '#53647f' }} axisLine={false} tickLine={false} />
          <Tooltip contentStyle={{ borderRadius: '10px', border: '1px solid #dbe5f2', fontSize: '12px', fontWeight: 700 }} />
          <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize: '12px', fontWeight: 700, paddingTop: '12px' }} />
          <Area type="monotone" dataKey="new" name="New Leads" stroke="#1f7ff0" strokeWidth={2.5} fill="url(#colorNew)" dot={{ r: 3, fill: '#1f7ff0' }} />
          <Area type="monotone" dataKey="follow_up" name="Follow-ups" stroke="#6b55e9" strokeWidth={2.5} fill="url(#colorFollowUp)" dot={{ r: 3, fill: '#6b55e9' }} />
          <Area type="monotone" dataKey="won" name="Won Leads" stroke="#36a269" strokeWidth={2.5} fill="url(#colorWon)" dot={{ r: 3, fill: '#36a269' }} />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

const STATUS_COLORS = {
  'New': '#1f7ff0',
  'Follow-up': '#36a269',
  'Quotation': '#f8c64d',
  'Won': '#6b55e9',
  'Lost': '#e44d4d',
};

function ReportDonut({ data, loading }) {
  if (loading) {
    return <PageLoadingState message="Loading chart..." className="h-[220px] py-0" compact />;
  }
  const chartData = (data || []).map(d => ({
    name: d.status,
    value: d.count,
    color: STATUS_COLORS[d.status] || '#94a3b8',
  }));
  const total = chartData.reduce((s, d) => s + d.value, 0);

  return (
    <div className="mt-4 flex flex-col gap-4 md:flex-row md:items-center">
      <div className="mx-auto h-[200px] w-[200px] shrink-0">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie data={chartData} cx="50%" cy="50%" innerRadius={55} outerRadius={90} paddingAngle={2} dataKey="value">
              {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={entry.color} />
              ))}
            </Pie>
            <Tooltip formatter={(value, name) => [value, name]} contentStyle={{ borderRadius: '10px', fontSize: '12px', fontWeight: 700 }} />
          </PieChart>
        </ResponsiveContainer>
      </div>
      <div className="flex-1 space-y-2">
        {chartData.map((item) => (
          <div key={item.name} className="flex items-center justify-between rounded-[8px] px-3 py-2 hover:bg-[#f8fbff]">
            <span className="flex items-center gap-2 text-[13px] font-bold text-[#1e3261]">
              <span className="size-2.5 rounded-full" style={{ backgroundColor: item.color }} />
              {item.name}
            </span>
            <span className="text-[13px] font-extrabold text-[#314a79]">
              {item.value} ({total ? ((item.value / total) * 100).toFixed(1) : 0}%)
            </span>
          </div>
        ))}
        <div className="mt-2 border-t border-[#edf2f8] pt-2 text-center text-[12px] font-extrabold text-[#53647f]">
          Total: {total} Leads
        </div>
      </div>
    </div>
  );
}

function ReportBarChart({ data, dataKey, nameKey, color = '#1f7ff0', loading }) {
  if (loading) {
    return <PageLoadingState message="Loading chart..." className="h-[220px] py-0" compact />;
  }
  if (!data || data.length === 0) {
    return <div className="flex h-[220px] items-center justify-center text-[13px] font-bold text-[#8a98af]">No data</div>;
  }
  return (
    <div className="h-[220px]">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} margin={{ top: 5, right: 10, left: -20, bottom: 5 }} layout="vertical">
          <CartesianGrid strokeDasharray="3 3" stroke="#edf2f8" horizontal={false} />
          <XAxis type="number" tick={{ fontSize: 11, fontWeight: 700, fill: '#53647f' }} axisLine={false} tickLine={false} />
          <YAxis type="category" dataKey={nameKey} tick={{ fontSize: 11, fontWeight: 700, fill: '#53647f' }} axisLine={false} tickLine={false} width={80} />
          <Tooltip contentStyle={{ borderRadius: '10px', fontSize: '12px', fontWeight: 700 }} />
          <Bar dataKey={dataKey} fill={color} radius={[0, 6, 6, 0]} maxBarSize={24} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

