const MONTHS_SHORT = { Jan:0, Feb:1, Mar:2, Apr:3, May:4, Jun:5, Jul:6, Aug:7, Sep:8, Oct:9, Nov:10, Dec:11 };
function isFollowUpOverdue(dateStr) {
  if (!dateStr) return false;
  const parts = dateStr.split(' ');
  if (parts.length !== 3) return false;
  const d = parseInt(parts[0], 10);
  const m = MONTHS_SHORT[parts[1]];
  const y = parseInt(parts[2], 10);
  if (Number.isNaN(d) || m === undefined || Number.isNaN(y)) return false;
  const followUpDate = new Date(y, m, d);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return followUpDate < today;
}

function formatReportDate(value) {
  const date = new Date(`${value}T00:00:00`);
  if (Number.isNaN(date.getTime())) {
    return value;
  }

  return date.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric',
  });
}

function parseDashboardDate(value) {
  if (!value) {
    return null;
  }

  const normalized = String(value).replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
  const explicitDateMatch = normalized.match(/(\d{1,2}\s+[A-Za-z]{3}\s+\d{4})/);
  if (explicitDateMatch) {
    const explicitDate = new Date(`${explicitDateMatch[1]} 00:00:00`);
    if (!Number.isNaN(explicitDate.getTime())) {
      return explicitDate;
    }
  }

  const isoDateMatch = normalized.match(/(\d{4}-\d{2}-\d{2})/);
  if (isoDateMatch) {
    const isoDate = new Date(`${isoDateMatch[1]}T00:00:00`);
    if (!Number.isNaN(isoDate.getTime())) {
      return isoDate;
    }
  }

  const fallbackDate = new Date(normalized);
  if (!Number.isNaN(fallbackDate.getTime())) {
    return fallbackDate;
  }

  return null;
}

function isDateWithinRange(value, dateFrom, dateTo) {
  const parsedValue = parseDashboardDate(value);
  if (!parsedValue) {
    return true;
  }

  const rangeStart = new Date(`${dateFrom}T00:00:00`);
  const rangeEnd = new Date(`${dateTo}T23:59:59`);
  if (Number.isNaN(rangeStart.getTime()) || Number.isNaN(rangeEnd.getTime())) {
    return true;
  }

  return parsedValue >= rangeStart && parsedValue <= rangeEnd;
}

let cachedEmployeeOptions = null;
let employeeOptionsPromise = null;

function getEmployeeOptions() {
  if (cachedEmployeeOptions) return Promise.resolve(cachedEmployeeOptions);
  if (!employeeOptionsPromise) {
    employeeOptionsPromise = userApi.list({ is_active: true })
      .then((data) => {
        const users = normalizeApiRows(data);
        cachedEmployeeOptions = users.map((user) => ({ label: user.name || user.email, value: String(user.id) }));
        return cachedEmployeeOptions;
      })
      .catch(() => {
        cachedEmployeeOptions = [];
        return cachedEmployeeOptions;
      });
  }
  return employeeOptionsPromise;
}

function useIvrsCheck(excludeId) {
  const [checking, setChecking] = useState(false);
  const [result, setResult] = useState(null);

  const check = async (value) => {
    const ivrs = (value || '').trim();
    if (!ivrs) { setResult(null); return; }
    setChecking(true);
    try {
      const data = await leadApi.list({ search: ivrs });
      const rows = Array.isArray(data) ? data : (data?.results ?? []);
      const match = rows.find((row) => row.ivrs_number === ivrs && row.id !== excludeId);
      setResult(match || 'unique');
    } catch {
      setResult(null);
    } finally {
      setChecking(false);
    }
  };

  return { checking, result, check, reset: () => setResult(null) };
}

function LeadFormModal({ mode = 'create', lead, projectContext = null, projectCreate = false, onClose, onSaved, onRequestApproval, onNotify }) {
  const [duplicateModalOpen, setDuplicateModalOpen] = useState(false);
  const [duplicateIvrs, setDuplicateIvrs] = useState('');
  const [duplicateLeadMatches, setDuplicateLeadMatches] = useState([]);
  const [duplicateLeadPayload, setDuplicateLeadPayload] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [employeeOptions, setEmployeeOptions] = useState(cachedEmployeeOptions || []);
  const [detail, setDetail] = useState(mode === 'edit' ? null : {});
  const [loadingDetail, setLoadingDetail] = useState(mode === 'edit');
  const formRef = useRef(null);
  const [quotationTemplate, setQuotationTemplate] = useState('');
  const [quotationDetail, setQuotationDetail] = useState(null);
  const [showQuotationDetailModal, setShowQuotationDetailModal] = useState(false);
  const [viewDuplicateLeadId, setViewDuplicateLeadId] = useState(null);
  const [surveyModalOpen, setSurveyModalOpen] = useState(false);
  const [projectSurveyForQuote, setProjectSurveyForQuote] = useState(null);
  const ivrsCheck = useIvrsCheck(lead?.id);
  // "Project Details Update" (edit) aur "New Project" (create) dono project popups —
  // in dono me lead status fixed 'Won' rehta hai aur follow-up date optional hai.
  const projectMode = Boolean(projectContext) || projectCreate;

  useEffect(() => {
    getEmployeeOptions().then(setEmployeeOptions);
  }, []);

  useEffect(() => {
    if (mode !== 'edit' || !lead?.id) { setDetail({}); setLoadingDetail(false); return; }
    setLoadingDetail(true);
    leadApi.get(lead.id).then((data) => setDetail(data || {})).catch(() => setDetail({})).finally(() => setLoadingDetail(false));
  }, [mode, lead?.id]);

  // Project already has a site survey by this point (Won lead) — pull it in
  // so a quotation started from here doesn't need roof/capacity re-typed.
  useEffect(() => {
    if (!projectContext?.projectId) { setProjectSurveyForQuote(null); return; }
    projectApi.get(projectContext.projectId).then((data) => setProjectSurveyForQuote(data?.site_survey || null)).catch(() => {});
  }, [projectContext?.projectId]);

  const handleSubmit = async (event) => {
    event.preventDefault();
    const fd = new FormData(event.currentTarget);
    const mobile = fd.get('mobile_number')?.trim();
    const ivrs = fd.get('ivrs_number')?.trim();

    setSubmitting(true);
    setSubmitError('');
    const payload = {
      customer_name: fd.get('customer_name'),
      mobile_number: mobile,
      ivrs_number: ivrs || undefined,
      alternate_number: fd.get('alternate_number') || undefined,
      email: fd.get('email') || undefined,
      project_name: fd.get('project_name') || undefined,
      project_type: fd.get('project_type') || undefined,
      requirement_details: fd.get('requirement_details') || undefined,
      source: fd.get('source') || undefined,
      estimated_capacity: fd.get('estimated_capacity') || undefined,
      next_follow_up: fd.get('next_follow_up') || undefined,
      assigned_to: fd.get('assigned_to') || undefined,
      ...(!projectMode && (() => {
        const bucketStatusMap = {
          new: { status: 'New', priority: '' },
          hot: { status: 'New', priority: 'High' },
          warm: { status: 'Follow-up', priority: '' },
          cool: { status: 'New', priority: 'Low' },
          lost: { status: 'Lost', priority: '' },
          won: { status: 'Won', priority: '' },
        };
        const bucket = fd.get('lead_bucket') || 'new';
        return bucketStatusMap[bucket] || { status: 'New', priority: '' };
      })()),
      ...(projectMode && { status: 'Won', priority: '' }),
      remarks: fd.get('remarks') || undefined,
      address: fd.get('address') || undefined,
      city: fd.get('city') || undefined,
      state: fd.get('state') || undefined,
      latitude: fd.get('latitude') || undefined,
      longitude: fd.get('longitude') || undefined,
    };

    try {
      if (projectContext) {
        await projectApi.update(projectContext.projectId, { status: fd.get('project_status') || projectContext.status });
        const savedProjectLead = projectContext.leadId ? await leadApi.update(projectContext.leadId, payload) : null;
        onNotify?.('Project details updated successfully!');
        onSaved?.(savedProjectLead);
        return;
      }
      let savedLead;
      if (mode === 'edit') {
        savedLead = await leadApi.update(lead.id, payload);
        onNotify?.('Lead updated successfully!');
      } else {
        savedLead = await leadApi.create(payload);
        // New Project: 'Won' lead create karte hi backend signal apne aap Project bana deta hai
        // (status 'Planning'). Agar user ne dusra status chuna hai to wo project pe apply kar do.
        if (projectCreate) {
          const chosenStatus = fd.get('project_status') || 'Planning';
          if (chosenStatus && chosenStatus !== 'Planning') {
            try {
              const projs = await projectApi.list({ lead: savedLead.id });
              const list = Array.isArray(projs) ? projs : projs?.results ?? [];
              if (list[0]?.id) await projectApi.update(list[0].id, { status: chosenStatus });
            } catch { /* status update non-fatal */ }
          }
        }
        onNotify?.(projectCreate ? 'Project created successfully!' : 'Lead created successfully!');
      }

      if (quotationDetail) {
        quotationApi.create(buildQuotationDetailPayload(quotationDetail.template, quotationDetail.form, savedLead.id, quotationDetail.items)).catch(() => {});
      }

      onSaved?.(savedLead);
    } catch (err) {
      if (mode === 'create' && err.message?.toLowerCase().includes('ivrs number already exists')) {
        const matches = await leadApi.list({ search: ivrs }).catch(() => null);
        const matchRows = matches ? (Array.isArray(matches) ? matches : matches.results ?? []) : [];
        setDuplicateLeadMatches(matchRows.filter((row) => row.ivrs_number === ivrs));
        setDuplicateLeadPayload(payload);
        setDuplicateIvrs(ivrs);
        setDuplicateModalOpen(true);
      } else {
        setSubmitError(err.message || 'Error saving lead. Please try again.');
      }
    } finally {
      setSubmitting(false);
    }
  };

  const d = detail || {};
  const followUpDateValue = d.next_follow_up ? new Date(d.next_follow_up).toISOString().slice(0, 10) : '';

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/55 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex max-h-[92vh] w-full max-w-[860px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between border-b border-[#edf2f8] px-6 py-4">
          <h2 className="font-display text-[18px] font-extrabold text-[#111827]">
            {projectContext ? 'Project Details Update' : projectCreate ? 'New Project' : mode === 'edit' ? 'Edit Lead' : 'Create Lead'}
          </h2>
          <button type="button" onClick={onClose} aria-label="Close" title="Close" className="text-[#7585a2]"><X className="size-5" /></button>
        </div>

        <div className="scroll-soft flex-1 overflow-y-auto p-6">
          {submitError ? (
            <div className="mb-4 rounded-[8px] border border-red-200 bg-red-50 px-4 py-3 text-[13px] font-bold text-red-600">
              {submitError}
            </div>
          ) : null}

          {loadingDetail ? (
            <PageLoadingState message="Loading lead..." />
          ) : (
          <form id="lead-form-modal" ref={formRef} className="space-y-4" onSubmit={handleSubmit}>
            {projectMode ? (
              <LeadFormSection title="Project Status" icon={FolderKanban} tone="primary">
                <div className="grid gap-4 lg:grid-cols-3">
                  <LeadSelect label="Status" placeholder="Select status" options={['Planning', 'Active', 'On Hold', 'Completed', 'Cancelled']} name="project_status" defaultValue={projectContext ? projectContext.status : 'Planning'} />
                </div>
              </LeadFormSection>
            ) : null}
            <LeadFormSection title="1. Basic Information" icon={ReceiptText} tone="success">
              <div className="grid gap-4 lg:grid-cols-3">
                <LeadInput label="Customer Name" required icon={UserRound} placeholder="Enter customer name" name="customer_name" defaultValue={d.customer_name} />
                <LeadPhoneInput label="Mobile Number" required placeholder="Enter mobile number" name="mobile_number" defaultValue={d.mobile_number} />
                <IvrsVerifyField
                  defaultValue={d.ivrs_number}
                  checking={ivrsCheck.checking}
                  result={ivrsCheck.result}
                  onCheck={ivrsCheck.check}
                  onReset={ivrsCheck.reset}
                  onShowDetail={setViewDuplicateLeadId}
                />
              </div>
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadPhoneInput label="Alternate Number" placeholder="Enter alternate number" name="alternate_number" defaultValue={d.alternate_number} />
                <LeadInput label="Email Address" icon={Mail} placeholder="Enter email address" type="email" name="email" defaultValue={d.email} />
              </div>
            </LeadFormSection>

            <LeadFormSection title="2. Project Information" icon={ClipboardPlus} tone="primary">
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadInput label="Project Name" icon={FolderKanban} placeholder="Enter project name" name="project_name" defaultValue={d.project_name} />
                <LeadSelect label="Project Type" placeholder="Select project type" options={['On-Grid', 'Off-Grid', 'Hybrid']} name="project_type" defaultValue={d.project_type} />
              </div>
              <LeadTextarea label="Requirement Details" icon={Users} placeholder="Enter requirement details..." name="requirement_details" defaultValue={d.requirement_details} />
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadSelect label="Source" placeholder="Select source" options={['Website', 'Referral', 'Walk-in', 'Campaign']} name="source" defaultValue={d.source} />
                <LeadInput label="Estimated Capacity (kW)" icon={Zap} type="number" placeholder="Enter capacity (e.g. 5, 10, 20)" name="estimated_capacity" defaultValue={d.estimated_capacity} />
              </div>
            </LeadFormSection>

            <LeadFormSection title="3. Assignment & Follow-up" icon={UserRound} tone="purple">
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadDateInput label="Follow-up Date" required={!projectMode} name="next_follow_up" defaultValue={followUpDateValue} />
                {projectMode ? (
                  <LeadLockedField label="Lead Status" value="Won leads" />
                ) : (
                  <LeadSelect
                    label="Lead Status"
                    placeholder="Select status"
                    options={[
                      { value: 'new', label: 'New leads' },
                      { value: 'hot', label: 'Hot leads' },
                      { value: 'warm', label: 'Warm leads' },
                      { value: 'cool', label: 'Cool leads' },
                      { value: 'lost', label: 'Lost leads' },
                      { value: 'won', label: 'Won leads' },
                    ]}
                    name="lead_bucket"
                    defaultValue={mode === 'edit' ? (() => {
                      if (d.status === 'Lost') return 'lost';
                      if (d.status === 'Won') return 'won';
                      if (d.priority === 'High') return 'hot';
                      if (d.priority === 'Low') return 'cool';
                      if (d.status === 'Follow-up' || d.status === 'Quotation') return 'warm';
                      return 'new';
                    })() : 'new'}
                  />
                )}
              </div>
              <LeadTextarea label="Remarks" icon={MapPin} placeholder="Enter remarks (optional)" compact name="remarks" defaultValue={d.remarks} />
            </LeadFormSection>

            <LeadFormSection title="4. Location Information" titleSuffix="(Optional)" icon={MapPin} tone="warning">
              <LeadTextarea label="Address" icon={MapPin} placeholder="Enter full address" name="address" defaultValue={d.address} />
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadInput label="Latitude" optional icon={MapPin} placeholder="Enter latitude" name="latitude" defaultValue={d.latitude} />
                <LeadInput label="Longitude" optional icon={MapPin} placeholder="Enter longitude" name="longitude" defaultValue={d.longitude} />
              </div>
            </LeadFormSection>

            <LeadFormSection title="5. Quotation" titleSuffix="(Optional)" icon={ReceiptText} tone="primary">
              <p className="-mt-1 mb-1 text-[12px] font-bold text-[#7386a3]">Pick a quotation template, fill its detail in a separate form, then save it here. Manage full quotations later from the lead's details page.</p>
              <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
                {QUOTATION_TEMPLATE_OPTIONS.map((option) => {
                  const active = quotationTemplate === option;
                  const savedForThis = quotationDetail && quotationTemplate === option;
                  return (
                    <button
                      key={option}
                      type="button"
                      onClick={() => setQuotationTemplate(option)}
                      className={cx(
                        'flex items-center justify-between gap-2 rounded-[10px] border px-4 py-3 text-left text-[13px] font-extrabold transition',
                        active ? 'border-[#0b65e5] bg-[#edf5ff] text-[#0b65e5]' : 'border-[#dbe5f2] bg-white text-[#30466d] hover:bg-[#f8fbff]',
                      )}
                    >
                      {option}
                      {savedForThis ? <CheckCircle2 className="size-4 shrink-0 text-[#0d9f4a]" /> : null}
                    </button>
                  );
                })}
              </div>
              <button
                type="button"
                disabled={!quotationTemplate}
                onClick={() => setShowQuotationDetailModal(true)}
                className="inline-flex h-11 items-center gap-2 rounded-[8px] border border-[#0b65e5] bg-white px-4 text-[13px] font-extrabold text-[#0b65e5] transition hover:bg-[#edf5ff] disabled:cursor-not-allowed disabled:opacity-50"
              >
                <FileText className="size-4" />
                {quotationDetail && quotationTemplate === quotationDetail.template ? 'Edit Detail' : 'Fill Detail'}
              </button>
              {quotationDetail && quotationTemplate === quotationDetail.template ? (
                <p className="text-[12px] font-bold text-[#087a39]">Detail saved for {quotationDetail.template}. It will be created with this lead.</p>
              ) : null}
            </LeadFormSection>

            <LeadFormSection title="6. Assigned To" titleSuffix="(Optional)" icon={UserRound} tone="purple">
              <LeadSelect label="Assigned Employee" optional placeholder={employeeOptions.length ? 'Select employee' : 'No active employees found'} options={employeeOptions} name="assigned_to" defaultValue={d.assigned_to ? String(d.assigned_to) : ''} />
            </LeadFormSection>

            {!projectMode && mode === 'edit' && lead?.id ? (
              <LeadFormSection title="7. Site Survey" titleSuffix="(Optional)" icon={MapPin} tone="warning">
                <p className="-mt-1 mb-1 text-[12px] font-bold text-[#7386a3]">
                  Capture a quick site inspection (address, lat/long, roof type, size, customer feedback, photos). This gets copied automatically into the Project Management site survey once this lead is won.
                </p>
                <button
                  type="button"
                  onClick={() => setSurveyModalOpen(true)}
                  className="inline-flex h-11 items-center gap-2 rounded-[8px] border border-[#0b65e5] bg-white px-4 text-[13px] font-extrabold text-[#0b65e5] transition hover:bg-[#edf5ff]"
                >
                  <MapPin className="size-4" />
                  {d.site_survey?.status === 'Completed' ? 'View Survey' : d.site_survey?.status === 'In Progress' ? 'Continue Survey' : 'Start Survey'}
                </button>
              </LeadFormSection>
            ) : null}
          </form>
          )}
        </div>

        <div className="flex flex-col justify-end gap-3 border-t border-[#edf2f8] px-6 py-4 sm:flex-row">
          <button type="button" onClick={onClose} className="h-11 rounded-[8px] border border-black/20 bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff]">
            Cancel
          </button>
          <button
            type="submit"
            form="lead-form-modal"
            disabled={submitting || loadingDetail}
            className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#10a64e] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(18,165,79,0.22)] transition hover:bg-[#0e9145] disabled:opacity-60"
          >
            <Save className="size-4" />
            {submitting ? 'Saving...' : projectContext ? 'Update Project' : projectCreate ? 'Create Project' : mode === 'edit' ? 'Update Lead' : 'Save Lead'}
          </button>
        </div>
      </div>

      {duplicateModalOpen ? (
        <DuplicateIvrsModal
          ivrsNumber={duplicateIvrs}
          existingLeads={duplicateLeadMatches}
          requestedLead={duplicateLeadPayload}
          onClose={() => {
            setDuplicateModalOpen(false);
            setDuplicateLeadPayload(null);
          }}
          onRequestApproval={() => {
            setDuplicateModalOpen(false);
            setDuplicateLeadPayload(null);
            onRequestApproval?.();
          }}
          onNotify={onNotify}
        />
      ) : null}

      {showQuotationDetailModal ? (
        <QuotationDetailModal
          template={quotationTemplate}
          initialForm={quotationTemplate === quotationDetail?.template ? quotationDetail.form : null}
          initialItems={quotationTemplate === quotationDetail?.template ? quotationDetail.items : null}
          leadSnapshot={(() => {
            const snap = formRef.current ? new FormData(formRef.current) : null;
            const survey = projectSurveyForQuote;
            return {
              customer_name: snap?.get('customer_name') || '',
              mobile_number: snap?.get('mobile_number') || '',
              alternate_number: snap?.get('alternate_number') || '',
              email: snap?.get('email') || '',
              address: snap?.get('address') || '',
              project_name: snap?.get('project_name') || '',
              source: snap?.get('source') || '',
              // From the project's site survey — already captured on-site, no re-typing.
              shadow_free_area: survey?.shadow_free_area_sqft || '',
              installation_type: deriveInstallationTypeFromRoof(survey?.roof_type),
              plant_capacity_kw: extractLeadingNumber(survey?.approx_plant_capacity),
              module_orientation: survey?.module_orientation || '',
            };
          })()}
          onClose={() => setShowQuotationDetailModal(false)}
          onTemplateChange={setQuotationTemplate}
          onSave={(savedTemplate, form, items) => {
            setQuotationTemplate(savedTemplate);
            setQuotationDetail({ template: savedTemplate, form, items });
            setShowQuotationDetailModal(false);
          }}
        />
      ) : null}

      {viewDuplicateLeadId ? (
        <LeadViewModal
          leadId={viewDuplicateLeadId}
          onClose={() => setViewDuplicateLeadId(null)}
          onEdit={() => setViewDuplicateLeadId(null)}
          onNotify={onNotify}
        />
      ) : null}

      {surveyModalOpen && lead?.id ? (
        <LeadSiteSurveyModal
          leadId={lead.id}
          customerName={d.customer_name}
          onClose={() => setSurveyModalOpen(false)}
          onSaved={(saved) => setDetail((prev) => ({ ...prev, site_survey: saved }))}
          onNotify={onNotify}
        />
      ) : null}
    </div>
  );
}

const LEAD_SURVEY_MOUNTING_OPTIONS = ['Ground Mount', 'Roof / Terrace Mount', 'Tin Shed Mount'];

// Lightweight site inspection captured at the lead stage (before the lead is
// won) — separate from the fuller Project Management > Site Survey, which
// happens after conversion and gets auto-filled from this one.
function LeadSiteSurveyModal({ leadId, customerName, onClose, onSaved, onNotify }) {
  const [loading, setLoading] = useState(true);
  const [survey, setSurvey] = useState(null);
  const [form, setForm] = useState({
    status: 'In Progress', site_address: '', latitude: '', longitude: '', mounting_type: '',
    site_size_sqft: '', customer_feedback: '', survey_date: '',
  });
  const [saving, setSaving] = useState(false);
  const [locating, setLocating] = useState(false);
  const [locationError, setLocationError] = useState('');
  const [mapPickerOpen, setMapPickerOpen] = useState(false);
  const [uploadingPhoto, setUploadingPhoto] = useState(false);
  const fileInputRef = useRef(null);
  const cameraInputRef = useRef(null);

  useEffect(() => {
    let cancelled = false;
    leadApi.getSiteSurvey(leadId).then((data) => {
      if (cancelled) return;
      setSurvey(data);
      if (data) {
        setForm({
          status: data.status || 'In Progress',
          site_address: data.site_address || '',
          latitude: data.latitude || '',
          longitude: data.longitude || '',
          mounting_type: data.mounting_type || '',
          site_size_sqft: data.site_size_sqft || '',
          customer_feedback: data.customer_feedback || '',
          survey_date: data.survey_date || '',
        });
      }
    }).catch(() => {
      onNotify?.('Could not load site survey', 'error');
    }).finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [leadId]);

  const handleUseLocation = () => {
    if (!navigator.geolocation) {
      setLocationError('Location is not supported on this device/browser.');
      return;
    }
    setLocating(true);
    setLocationError('');
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const lat = position.coords.latitude.toFixed(6);
        const lng = position.coords.longitude.toFixed(6);
        setForm((f) => ({ ...f, latitude: lat, longitude: lng }));
        setLocating(false);

        // Best-effort reverse geocode into the address field too — location fix
        // already succeeded, so a failure here shouldn't surface as an error.
        loadGoogleMapsApi().then((maps) => {
          new maps.Geocoder().geocode({ location: { lat: Number(lat), lng: Number(lng) } }, (results, status) => {
            if (status === 'OK' && results?.[0]) {
              setForm((f) => ({ ...f, site_address: results[0].formatted_address }));
            }
          });
        }).catch(() => {});
      },
      (error) => {
        setLocating(false);
        if (error.code === error.PERMISSION_DENIED) {
          setLocationError('Location access is blocked for this site. Allow location permission in your browser/device settings, then tap Retry.');
        } else {
          setLocationError('Could not fetch location — make sure Location/GPS is turned on for this device, then tap Retry.');
        }
      },
      { enableHighAccuracy: true, timeout: 10000 },
    );
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const saved = await leadApi.saveSiteSurvey(leadId, { ...form, survey_date: form.survey_date || null });
      setSurvey(saved);
      onNotify?.('Site survey saved');
      onSaved?.(saved);
    } catch (err) {
      onNotify?.(err?.message || 'Failed to save site survey', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleUploadPhotos = async (event) => {
    const files = Array.from(event.target.files || []);
    event.target.value = '';
    if (!files.length) return;
    if (!survey?.id) {
      onNotify?.('Save the survey once before adding photos', 'error');
      return;
    }
    setUploadingPhoto(true);
    try {
      for (const file of files) {
        const fd = new FormData();
        fd.append('survey', survey.id);
        fd.append('image', file);
        await leadSurveyPhotoApi.create(fd);
      }
      const refreshed = await leadApi.getSiteSurvey(leadId);
      setSurvey(refreshed);
      onNotify?.('Photo(s) uploaded');
    } catch (err) {
      onNotify?.(err?.message || 'Failed to upload photo(s)', 'error');
    } finally {
      setUploadingPhoto(false);
    }
  };

  const handleDeletePhoto = async (photoId) => {
    try {
      await leadSurveyPhotoApi.delete(photoId);
      const refreshed = await leadApi.getSiteSurvey(leadId);
      setSurvey(refreshed);
    } catch (err) {
      onNotify?.(err?.message || 'Failed to delete photo', 'error');
    }
  };

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/55 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex max-h-[92vh] w-full max-w-[640px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between border-b border-[#edf2f8] px-6 py-4">
          <div>
            <h2 className="font-display text-[18px] font-extrabold text-[#111827]">Site Survey</h2>
            {customerName ? <p className="mt-0.5 text-[12px] font-bold text-[#7386a3]">{customerName}</p> : null}
          </div>
          <button type="button" onClick={onClose} aria-label="Close" title="Close" className="text-[#7585a2]"><X className="size-5" /></button>
        </div>

        <div className="scroll-soft flex-1 overflow-y-auto p-6">
          {loading ? (
            <PageLoadingState message="Loading survey..." />
          ) : (
            <div className="space-y-5">
              <label className="block min-w-0">
                <LeadLabel label="Status" />
                <span className="mt-2 flex h-11 items-center gap-3 rounded-[8px] border border-black/20 bg-white px-3 transition focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-100">
                  <select
                    value={form.status}
                    onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                    className="min-w-0 flex-1 bg-transparent text-[13px] font-bold text-[#30466d] outline-none"
                  >
                    <option value="Pending">🔴 Pending</option>
                    <option value="In Progress">🟡 In Progress</option>
                    <option value="Completed">🟢 Completed</option>
                  </select>
                </span>
              </label>

              {form.status === 'Completed' ? (
                <p className="rounded-[8px] bg-[#e8f8eb] px-3 py-2 text-[12px] font-extrabold text-[#0d9f4a]">
                  This survey is marked completed. You can still edit and re-save it.
                </p>
              ) : null}

              <div>
                <div className="mb-2 flex flex-wrap items-center justify-between gap-2">
                  <span className="text-[12px] font-extrabold text-[#34466c]">Site Details / Address, Latitude &amp; Longitude</span>
                  <div className="flex flex-wrap gap-2">
                    <button
                      type="button"
                      onClick={handleUseLocation}
                      disabled={locating}
                      className="inline-flex items-center gap-1.5 rounded-[7px] border border-[#d9e4f2] bg-white px-2.5 py-1.5 text-[12px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff] disabled:opacity-60"
                    >
                      <Crosshair className="size-3.5" />
                      {locating ? 'Locating...' : 'Use My Location'}
                    </button>
                    <button
                      type="button"
                      onClick={() => setMapPickerOpen(true)}
                      className="inline-flex items-center gap-1.5 rounded-[7px] border border-[#d9e4f2] bg-white px-2.5 py-1.5 text-[12px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff]"
                    >
                      <MapPin className="size-3.5" />
                      Manually
                    </button>
                  </div>
                </div>
                <p className="mb-2 text-[11px] font-bold text-[#8a98af]">Either button fills the address and lat/long together — you can also edit any field by hand.</p>
                {locationError ? (
                  <div className="mb-2 flex flex-wrap items-center justify-between gap-2 rounded-[8px] border border-[#f6dda9] bg-[#fff8e8] px-3 py-2 text-[12px] font-bold text-[#a76200]">
                    <span className="inline-flex items-center gap-1.5"><AlertTriangle className="size-3.5 shrink-0" />{locationError}</span>
                    <button
                      type="button"
                      onClick={handleUseLocation}
                      className="inline-flex shrink-0 items-center gap-1 rounded-[6px] border border-[#f6dda9] bg-white px-2.5 py-1 text-[11px] font-extrabold text-[#a76200] transition hover:bg-[#fff3d6]"
                    >
                      <RefreshCw className="size-3" />
                      Retry
                    </button>
                  </div>
                ) : null}

                <label className="block min-w-0">
                  <span className="flex min-h-[74px] items-start gap-3 rounded-[8px] border border-black/20 bg-white px-3 py-3 transition focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-100">
                    <MapPin className="mt-0.5 size-4 shrink-0 text-[#8391a8]" />
                    <textarea
                      placeholder="Site address, landmark, access notes"
                      rows={3}
                      value={form.site_address}
                      onChange={(e) => setForm((f) => ({ ...f, site_address: e.target.value }))}
                      className="min-h-full min-w-0 flex-1 resize-y bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a98af]"
                    />
                  </span>
                </label>

                <div className="mt-3 grid gap-4 sm:grid-cols-2">
                  <label className="block min-w-0">
                    <span className="flex h-11 items-center gap-3 rounded-[8px] border border-black/20 bg-white px-3 transition focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-100">
                      <MapPin className="size-4 shrink-0 text-[#8391a8]" />
                      <input
                        type="text"
                        placeholder="Latitude"
                        value={form.latitude}
                        onChange={(e) => setForm((f) => ({ ...f, latitude: e.target.value }))}
                        className="min-w-0 flex-1 bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a98af]"
                      />
                    </span>
                  </label>
                  <label className="block min-w-0">
                    <span className="flex h-11 items-center gap-3 rounded-[8px] border border-black/20 bg-white px-3 transition focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-100">
                      <MapPin className="size-4 shrink-0 text-[#8391a8]" />
                      <input
                        type="text"
                        placeholder="Longitude"
                        value={form.longitude}
                        onChange={(e) => setForm((f) => ({ ...f, longitude: e.target.value }))}
                        className="min-w-0 flex-1 bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a98af]"
                      />
                    </span>
                  </label>
                </div>
              </div>

              <div>
                <span className="mb-2 block text-[12px] font-extrabold text-[#34466c]">Mounting Type</span>
                <div className="grid gap-2 sm:grid-cols-3">
                  {LEAD_SURVEY_MOUNTING_OPTIONS.map((option) => (
                    <button
                      key={option}
                      type="button"
                      onClick={() => setForm((f) => ({ ...f, mounting_type: option }))}
                      className={cx(
                        'rounded-[8px] border px-3 py-2.5 text-[12px] font-extrabold transition',
                        form.mounting_type === option
                          ? 'border-[#0b65e5] bg-[#edf5ff] text-[#0b65e5]'
                          : 'border-[#dbe5f2] bg-white text-[#30466d] hover:bg-[#f8fbff]',
                      )}
                    >
                      {option}
                    </button>
                  ))}
                </div>
              </div>

              <label className="block min-w-0">
                <LeadLabel label="Site / Roof Size (sq. ft.)" optional />
                <span className="mt-2 flex h-11 items-center gap-3 rounded-[8px] border border-black/20 bg-white px-3 transition focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-100">
                  <input
                    type="text"
                    placeholder="e.g. 850"
                    value={form.site_size_sqft}
                    onChange={(e) => setForm((f) => ({ ...f, site_size_sqft: e.target.value }))}
                    className="min-w-0 flex-1 bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a98af]"
                  />
                </span>
              </label>

              <label className="block min-w-0">
                <LeadLabel label="Customer Feedback" optional />
                <span className="mt-2 flex min-h-[62px] items-start gap-3 rounded-[8px] border border-black/20 bg-white px-3 py-3 transition focus-within:border-blue-500 focus-within:ring-4 focus-within:ring-blue-100">
                  <textarea
                    placeholder="Customer's feedback / expectations from the site visit"
                    rows={2}
                    value={form.customer_feedback}
                    onChange={(e) => setForm((f) => ({ ...f, customer_feedback: e.target.value }))}
                    className="min-h-full min-w-0 flex-1 resize-y bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a98af]"
                  />
                </span>
              </label>

              <div>
                <div className="mb-2 flex items-center justify-between gap-2">
                  <span className="text-[12px] font-extrabold text-[#34466c]">Site Photos</span>
                  <div className="flex flex-wrap gap-2">
                    <button
                      type="button"
                      onClick={() => fileInputRef.current?.click()}
                      disabled={uploadingPhoto}
                      className="inline-flex items-center gap-1.5 rounded-[7px] border border-[#d9e4f2] bg-white px-2.5 py-1.5 text-[12px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff] disabled:opacity-60"
                    >
                      <Upload className="size-3.5" />
                      {uploadingPhoto ? 'Uploading...' : 'Upload'}
                    </button>
                    <button
                      type="button"
                      onClick={() => cameraInputRef.current?.click()}
                      disabled={uploadingPhoto}
                      className="inline-flex items-center gap-1.5 rounded-[7px] border border-[#d9e4f2] bg-white px-2.5 py-1.5 text-[12px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff] disabled:opacity-60"
                    >
                      <Camera className="size-3.5" />
                      Camera
                    </button>
                  </div>
                  <input ref={fileInputRef} type="file" multiple accept="image/*" className="hidden" onChange={handleUploadPhotos} />
                  <input ref={cameraInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handleUploadPhotos} />
                </div>
                <div className="grid grid-cols-3 gap-2 sm:grid-cols-4">
                  {(survey?.photos ?? []).length === 0 ? (
                    <p className="col-span-full text-[12px] font-bold text-[#8a98af]">No photos uploaded yet.</p>
                  ) : survey.photos.map((photo) => (
                    <div key={photo.id} className="group relative overflow-hidden rounded-[8px] border border-[#e7eef7]">
                      <img src={getMediaUrl(photo.image)} alt="Site" className="h-20 w-full object-cover" />
                      <button
                        type="button"
                        onClick={() => handleDeletePhoto(photo.id)}
                        aria-label="Remove photo"
                        className="absolute right-1 top-1 hidden size-6 items-center justify-center rounded-full bg-black/60 text-white group-hover:flex"
                      >
                        <X className="size-3.5" />
                      </button>
                    </div>
                  ))}
                </div>
                {!survey?.id ? (
                  <p className="mt-1.5 text-[11px] font-bold text-[#8a98af]">Save the survey once to enable photo uploads.</p>
                ) : null}
              </div>
            </div>
          )}
        </div>

        <div className="flex flex-col justify-end gap-3 border-t border-[#edf2f8] px-6 py-4 sm:flex-row">
          <button type="button" onClick={onClose} className="h-11 rounded-[8px] border border-black/20 bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff]">
            Close
          </button>
          <button
            type="button"
            onClick={handleSave}
            disabled={saving || loading}
            className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#10a64e] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(18,165,79,0.22)] transition hover:bg-[#0e9145] disabled:opacity-60"
          >
            <Save className="size-4" />
            {saving ? 'Saving...' : 'Save'}
          </button>
        </div>
      </div>

      {mapPickerOpen ? (
        <LeadSurveyMapPickerModal
          initialLat={form.latitude}
          initialLng={form.longitude}
          onClose={() => setMapPickerOpen(false)}
          onConfirm={(lat, lng, address) => {
            setForm((f) => ({ ...f, latitude: lat, longitude: lng, site_address: address || f.site_address }));
            setLocationError('');
            setMapPickerOpen(false);
          }}
        />
      ) : null}
    </div>
  );
}

// Real Google Maps picker — click or drag the pin to set a location, or search
// an address. Also reverse-geocodes the picked point into a formatted address
// so the caller can fill both the lat/long fields and the address text.
const LEAD_SURVEY_DEFAULT_MAP_CENTER = { lat: 22.7196, lng: 75.8577 }; // Indore, HQ city

function LeadSurveyMapPickerModal({ initialLat, initialLng, onClose, onConfirm }) {
  const mapContainerRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const markerRef = useRef(null);
  const geocoderRef = useRef(null);
  const [position, setPosition] = useState(() => ({
    lat: initialLat ? parseFloat(initialLat) : LEAD_SURVEY_DEFAULT_MAP_CENTER.lat,
    lng: initialLng ? parseFloat(initialLng) : LEAD_SURVEY_DEFAULT_MAP_CENTER.lng,
  }));
  const [resolvedAddress, setResolvedAddress] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [searching, setSearching] = useState(false);
  const [searchError, setSearchError] = useState('');
  const [mapError, setMapError] = useState('');

  const reverseGeocode = useCallback((lat, lng) => {
    geocoderRef.current?.geocode({ location: { lat, lng } }, (results, status) => {
      if (status === 'OK' && results?.[0]) setResolvedAddress(results[0].formatted_address);
    });
  }, []);

  useEffect(() => {
    let cancelled = false;
    loadGoogleMapsApi().then((maps) => {
      if (cancelled || !mapContainerRef.current) return;

      const map = new maps.Map(mapContainerRef.current, {
        center: position,
        zoom: 15,
        streetViewControl: false,
        fullscreenControl: false,
        zoomControl: true,
        zoomControlOptions: { position: maps.ControlPosition.RIGHT_BOTTOM },
      });
      const marker = new maps.Marker({ position, map, draggable: true });
      marker.addListener('dragend', () => {
        const latLng = marker.getPosition();
        const next = { lat: latLng.lat(), lng: latLng.lng() };
        setPosition(next);
        reverseGeocode(next.lat, next.lng);
      });
      map.addListener('click', (event) => {
        const next = { lat: event.latLng.lat(), lng: event.latLng.lng() };
        marker.setPosition(next);
        setPosition(next);
        reverseGeocode(next.lat, next.lng);
      });

      // "My Location" button — Google Maps JS API has no built-in one, so this
      // adds a custom control matching the familiar circular target icon,
      // stacked above the zoom control.
      const locateButton = document.createElement('button');
      locateButton.type = 'button';
      locateButton.title = 'Show my location';
      locateButton.setAttribute('aria-label', 'Show my location');
      locateButton.style.cssText = 'margin:10px;width:40px;height:40px;border-radius:50%;background:#fff;border:none;box-shadow:0 1px 4px rgba(0,0,0,0.3);cursor:pointer;display:flex;align-items:center;justify-content:center;';
      locateButton.innerHTML = '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#3367d6" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="7"></circle><circle cx="12" cy="12" r="1.6" fill="#3367d6"></circle><line x1="12" y1="1" x2="12" y2="4"></line><line x1="12" y1="20" x2="12" y2="23"></line><line x1="1" y1="12" x2="4" y2="12"></line><line x1="20" y1="12" x2="23" y2="12"></line></svg>';
      locateButton.addEventListener('click', () => {
        if (!navigator.geolocation) return;
        navigator.geolocation.getCurrentPosition((geoPosition) => {
          const next = { lat: geoPosition.coords.latitude, lng: geoPosition.coords.longitude };
          map.setCenter(next);
          map.setZoom(16);
          marker.setPosition(next);
          setPosition(next);
          reverseGeocode(next.lat, next.lng);
        });
      });
      map.controls[maps.ControlPosition.RIGHT_BOTTOM].push(locateButton);

      mapInstanceRef.current = map;
      markerRef.current = marker;
      geocoderRef.current = new maps.Geocoder();
      geocoderRef.current.geocode({ location: position }, (results, status) => {
        if (!cancelled && status === 'OK' && results?.[0]) setResolvedAddress(results[0].formatted_address);
      });
    }).catch((err) => {
      if (!cancelled) setMapError(err?.message || 'Failed to load Google Maps');
    });
    return () => { cancelled = true; };
  }, []);

  const handleSearch = () => {
    const query = searchQuery.trim();
    if (!query || !geocoderRef.current) return;
    setSearching(true);
    setSearchError('');
    geocoderRef.current.geocode({ address: query }, (results, status) => {
      setSearching(false);
      if (status !== 'OK' || !results?.[0]) {
        setSearchError('No matching location found');
        return;
      }
      const loc = results[0].geometry.location;
      const next = { lat: loc.lat(), lng: loc.lng() };
      setPosition(next);
      setResolvedAddress(results[0].formatted_address);
      mapInstanceRef.current?.setCenter(next);
      mapInstanceRef.current?.setZoom(16);
      markerRef.current?.setPosition(next);
    });
  };

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/55 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex h-[85vh] w-full max-w-[860px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between border-b border-[#edf2f8] px-6 py-4">
          <h2 className="font-display text-[18px] font-extrabold text-[#111827]">Select Location on Map</h2>
          <button type="button" onClick={onClose} aria-label="Close" title="Close" className="text-[#7585a2]"><X className="size-5" /></button>
        </div>

        <div className="flex items-center gap-2 border-b border-[#edf2f8] px-6 py-3">
          <span className="flex h-10 flex-1 items-center gap-2 rounded-[8px] border border-black/20 bg-white px-3">
            <Search className="size-4 shrink-0 text-[#8391a8]" />
            <input
              type="text"
              placeholder="Search an address / place name"
              value={searchQuery}
              onChange={(event) => setSearchQuery(event.target.value)}
              onKeyDown={(event) => { if (event.key === 'Enter') { event.preventDefault(); handleSearch(); } }}
              className="min-w-0 flex-1 bg-transparent text-[13px] font-bold text-[#30466d] outline-none placeholder:text-[#8a98af]"
            />
          </span>
          <button
            type="button"
            onClick={handleSearch}
            disabled={searching}
            className="inline-flex h-10 shrink-0 items-center gap-1.5 rounded-[8px] bg-[#0b65e5] px-4 text-[13px] font-extrabold text-white transition hover:bg-[#0954c2] disabled:opacity-60"
          >
            {searching ? 'Searching...' : 'Search'}
          </button>
        </div>
        {searchError ? <p className="px-6 pt-2 text-[12px] font-bold text-[#e2594c]">{searchError}</p> : null}

        {mapError ? (
          <div className="flex flex-1 items-center justify-center px-6 text-center">
            <p className="text-[13px] font-bold text-[#e2594c]">{mapError}</p>
          </div>
        ) : (
          <div ref={mapContainerRef} className="min-h-0 flex-1" />
        )}

        <div className="flex flex-col gap-3 border-t border-[#edf2f8] px-6 py-4 sm:flex-row sm:items-center sm:justify-between">
          <div className="min-w-0">
            <p className="text-[12px] font-bold text-[#53647f]">
              Lat: <span className="font-extrabold text-[#30466d]">{position.lat.toFixed(6)}</span>
              {'   '}Lng: <span className="font-extrabold text-[#30466d]">{position.lng.toFixed(6)}</span>
            </p>
            {resolvedAddress ? <p className="mt-0.5 truncate text-[12px] font-bold text-[#8a98af]" title={resolvedAddress}>{resolvedAddress}</p> : null}
          </div>
          <div className="flex justify-end gap-3">
            <button type="button" onClick={onClose} className="h-11 rounded-[8px] border border-black/20 bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff]">
              Cancel
            </button>
            <button
              type="button"
              onClick={() => onConfirm(position.lat.toFixed(6), position.lng.toFixed(6), resolvedAddress)}
              disabled={Boolean(mapError)}
              className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#10a64e] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(18,165,79,0.22)] transition hover:bg-[#0e9145] disabled:opacity-60"
            >
              <MapPin className="size-4" />
              Use This Location
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function localDateKey(value) {
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return null;
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

// Lead List ke "View Follow-up" button se khulta hai — Today/Tomorrow/kisi bhi date ke
// saare leads ke follow-ups ek jagah dekhne ke liye, bina poori list filter kiye.
function LeadFollowUpsOverviewModal({ leads, onClose, onViewLead }) {
  const [filterMode, setFilterMode] = useState('all');
  const [customDate, setCustomDate] = useState('');

  const todayKey = localDateKey(new Date());
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowKey = localDateKey(tomorrow);
  const targetKey = filterMode === 'today' ? todayKey : filterMode === 'tomorrow' ? tomorrowKey : customDate;

  const filteredLeads = useMemo(() => {
    if (!leads || (filterMode === 'date' && !customDate)) return [];
    return leads
      .filter((lead) => lead.nextFollowUpRaw && (filterMode === 'all' || localDateKey(lead.nextFollowUpRaw) === targetKey))
      .sort((a, b) => new Date(a.nextFollowUpRaw) - new Date(b.nextFollowUpRaw));
  }, [leads, filterMode, customDate, targetKey]);

  const tabs = [
    { key: 'all', label: 'All Follow-ups' },
    { key: 'today', label: 'Today' },
    { key: 'tomorrow', label: 'Tomorrow' },
    { key: 'date', label: 'Pick a Date' },
  ];

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/50 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex max-h-[88vh] w-full max-w-[720px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between gap-3 border-b border-[#edf2f8] px-6 py-5">
          <h2 className="flex items-center gap-3 font-display text-[18px] font-extrabold text-[#111827]"><CalendarDays className="size-5 text-[#0b65e5]" /> Follow-ups</h2>
          <button type="button" onClick={onClose} className="text-[#7585a2] hover:text-[#111827]"><X className="size-5" /></button>
        </div>

        <div className="flex flex-wrap items-center gap-2 border-b border-[#edf2f8] px-6 py-4">
          {tabs.map((tab) => (
            <button
              key={tab.key}
              type="button"
              onClick={() => setFilterMode(tab.key)}
              className={cx(
                'rounded-[8px] px-4 py-2 text-[13px] font-extrabold transition',
                filterMode === tab.key ? 'bg-[#0b65e5] text-white' : 'border border-[#d9e4f2] bg-white text-[#284276] hover:bg-[#f8fbff]',
              )}
            >
              {tab.label}
            </button>
          ))}
          {filterMode === 'date' ? (
            <input
              type="date"
              value={customDate}
              onChange={(event) => setCustomDate(event.target.value)}
              className="h-10 rounded-[8px] border border-[#d9e4f2] bg-white px-3 text-[13px] font-bold text-[#30466d] outline-none transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
            />
          ) : null}
          <span className="ml-auto text-[12px] font-bold text-[#7b88a2]">{filteredLeads.length} follow-up{filteredLeads.length === 1 ? '' : 's'}</span>
        </div>

        <div className="scroll-soft divide-y divide-[#edf2f8] overflow-y-auto px-6">
          {!leads ? (
            <PageLoadingState message="Loading follow-ups..." compact />
          ) : filterMode === 'date' && !customDate ? (
            <p className="py-8 text-center text-[13px] font-bold text-[#53647f]">Pick a date to see follow-ups.</p>
          ) : filteredLeads.length === 0 ? (
            <p className="py-8 text-center text-[13px] font-bold text-[#53647f]">{filterMode === 'all' ? 'No follow-ups scheduled.' : 'No follow-ups scheduled for this day.'}</p>
          ) : filteredLeads.map((lead) => (
            <div key={lead.id} className="flex flex-wrap items-center justify-between gap-3 py-4">
              <div className="min-w-0">
                <p className="font-extrabold text-[#1e3261]">{lead.customer}</p>
                <p className="mt-0.5 text-[12px] font-bold text-[#53647f]">{lead.project} • {lead.mobile}</p>
              </div>
              <div className="flex items-center gap-4">
                <AssigneeCell assignee={lead.assignedTo} compact />
                <span className="text-[13px] font-extrabold text-[#0b65e5]">
                  {filterMode === 'all'
                    ? new Date(lead.nextFollowUpRaw).toLocaleString('en-IN', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' })
                    : new Date(lead.nextFollowUpRaw).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}
                </span>
                <button
                  type="button"
                  onClick={() => onViewLead(lead.id)}
                  className="inline-flex size-8 items-center justify-center rounded-[8px] border border-[#e3ebf7] bg-white text-[#3480ff] transition hover:bg-[#f5f9ff]"
                  aria-label={`View ${lead.customer}`}
                >
                  <Eye className="size-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
        <div className="h-5 shrink-0" />
      </div>
    </div>
  );
}

