function PersonAvatar({ tone, initials }) {
  const shirt =
    {
      amber: '#f59e0b',
      sky: '#2563eb',
      emerald: '#10b981',
    }[tone] ?? '#64748b';

  const hair =
    {
      amber: '#2d241d',
      sky: '#3a2e25',
      emerald: '#1f1a16',
    }[tone] ?? '#2d241d';

  return (
    <span className={cx('grid size-7 place-items-center overflow-hidden rounded-full shadow-[0_6px_12px_rgba(33,54,93,0.16)]', avatarToneMap[tone])}>
      <svg viewBox="0 0 28 28" className="size-full" aria-label={initials}>
        <rect width="28" height="28" rx="14" fill="#ffffff" fillOpacity="0.08" />
        <path d="M6 28c1-4.5 4-7 8-7s7 2.5 8 7" fill={shirt} />
        <circle cx="14" cy="12" r="5.5" fill="#f3c18f" />
        <path d="M8.7 11.7c0-4.7 2.4-7.7 5.8-7.7 3.7 0 6.6 2.9 6.1 8-1-1.2-2.2-2-3.3-2.8-.9 1-2.9 2.3-5.8 2.5-.8 0-1.8 0-2.8 0z" fill={hair} />
        <circle cx="12.2" cy="12.2" r="0.55" fill="#2a201a" />
        <circle cx="15.9" cy="12.2" r="0.55" fill="#2a201a" />
      </svg>
    </span>
  );
}

const initialsAvatarPalette = ['#0b65e5', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0ea5a4'];

function InitialsAvatar({ name, size = 30 }) {
  const initials = (name || '?')
    .split(' ')
    .filter(Boolean)
    .map((w) => w[0])
    .slice(0, 2)
    .join('')
    .toUpperCase();
  const hash = [...(name || '')].reduce((sum, ch) => sum + ch.charCodeAt(0), 0);
  const bg = initialsAvatarPalette[hash % initialsAvatarPalette.length];

  return (
    <span
      className="grid shrink-0 place-items-center rounded-full text-[11px] font-extrabold text-white"
      style={{ width: size, height: size, background: bg }}
    >
      {initials || '?'}
    </span>
  );
}

function RecentLeadRow({ lead, onView }) {
  return (
    <button
      type="button"
      onClick={onView}
      className="flex w-full items-center gap-3 py-2.5 text-left transition hover:bg-[#f8fbff]"
    >
      <InitialsAvatar name={lead.customer} />
      <span className="min-w-0 flex-1 truncate text-[13px] font-bold text-[#274072]">
        {lead.customer}
        <span className="font-semibold text-[#8895ab]"> · {lead.project} · {lead.assignedTo.name}</span>
      </span>
      <StatusBadge status={lead.status} />
    </button>
  );
}

function OverdueTabContent({ items, onViewAll }) {
  const list = items ?? [];

  return (
    <div className="p-3.5">
      <div className="divide-y divide-[#edf2f8] overflow-hidden rounded-[12px] border border-[#e5edf6] bg-[#fbfdff] px-4">
        {list.length === 0 ? (
          <p className="py-6 text-center text-[13px] font-semibold text-[#8895ab]">No overdue follow-ups</p>
        ) : null}
        {list.slice(0, 4).map((item) => (
          <div
            key={`${item.customer}-${item.project}`}
            className="grid grid-cols-1 gap-1 py-2.5 text-[13px] sm:grid-cols-[1.2fr_1fr_auto] sm:items-center sm:gap-3"
          >
            <p className="font-bold text-[#274072]">{item.customer}</p>
            <p className="font-semibold text-[#4e6282]">{item.project}</p>
            <p className="font-extrabold text-[#ea5a4c] sm:text-right">{item.delay}</p>
          </div>
        ))}
      </div>
      {list.length > 4 ? (
        <button
          type="button"
          onClick={onViewAll}
          className="mt-2.5 flex w-full items-center justify-center gap-1.5 text-[12px] font-extrabold text-[#2a64dd] hover:underline"
        >
          View All
          <ArrowRight className="size-3.5" />
        </button>
      ) : null}
    </div>
  );
}

function InfoCell({ label, value, valueNode, valueClass, large = false }) {
  return (
    <div className="min-w-0">
      <p className={cx('font-extrabold uppercase tracking-[0.08em] text-[#8a98af]', large ? 'text-[12.5px]' : 'text-[11px]')}>{label}</p>
      {valueNode ? (
        <div className="mt-1.5 min-w-0">{valueNode}</div>
      ) : (
        <p className={cx('mt-1.5 truncate font-bold text-[#314a79]', large ? 'text-[14.5px]' : 'text-[12px]', valueClass)}>{value}</p>
      )}
    </div>
  );
}

export default App;
